const QUESTIONS = [{"num": 1, "q": "Nhà nước do giai cấp thống trị lập nên để bảo vệ quyền và lợi ích của giai cấp mình là quan điểm của học thuyết?", "a": "Mác - Lênin", "b": "Thần học", "c": "Gia trưởng", "d": "Khế ước xã hội", "ans": "a"}, {"num": 2, "q": "Theo quan điểm của chủ nghĩa Mác-Lênin thì nguyên nhân chủ yếu làm xuất hiện Nhà nước là?", "a": "Do có sự phân hóa lao động trong xã hội", "b": "Do có sự phân hóa giai cấp và đấu tranh giai cấp trong xã hội", "c": "Do địa hình, khí hậu không thuận lợi nên con người phải hợp sức lại để phát triển sản xuất", "d": "Do các thành viên trong xã hội lập ra", "ans": "b"}, {"num": 3, "q": "Nhà nước chưa ra đời trong hình thái kinh tế - xã hội nào sau đây?", "a": "Hình thái kinh tế - xã hội Công xã nguyên thủy", "b": "Hình thái kinh tế - xã hội Cộng sản nguyên thủy", "c": "Hình thái kinh tế - xã hội Cộng sản chủ nghĩa", "d": "Hình thái kinh tế - xã hội Chiếm hữu nô lệ", "ans": "b"}, {"num": 4, "q": "Nước nào sau đây có hình thức cấu trúc nhà nước liên bang?", "a": "Việt Nam", "b": "Pháp", "c": "Nga", "d": "Xingapo", "ans": "c"}, {"num": 5, "q": "Nhà nước nào sau đây có hình thức cấu trúc là nhà nước đơn nhất?", "a": "Mêxicô", "b": "Thụy Sĩ", "c": "Việt Nam", "d": "Nga", "ans": "c"}, {"num": 6, "q": "Nhà nước CHXHCN Việt Nam có hình thức cấu trúc là?", "a": "Nhà nước đơn nhất", "b": "Nhà nước liên bang", "c": "Nhà nước liên minh", "d": "Nhà nước độc tài", "ans": "a"}, {"num": 7, "q": "Nhà nước nào sau đây có hình thức chính thể cộng hòa tổng thống?", "a": "Đức", "b": "Ấn Độ", "c": "Anh", "d": "Tất cả đều sai", "ans": "d"}, {"num": 8, "q": "Nhà nước là hiện tượng xã hội mang tính lịch sử, đây là khẳng định về nguồn gốc của nhà nước theo quan điểm của…?", "a": "Aristote", "b": "J.J.Rousseau", "c": "Plato", "d": "Chủ nghĩa Mác-Lênin", "ans": "d"}, {"num": 9, "q": "Tổ chức thị tộc trong xã hội Cộng sản nguyên thủy là?", "a": "Một tổ chức kinh tế", "b": "Một tập đoàn người có cùng quan hệ huyết thống", "c": "Một xã hội độc lập", "d": "Một đơn vị độc lập", "ans": "b"}, {"num": 10, "q": "Kiểu nhà nước đầu tiên trong lịch sử xã hội loài người là?", "a": "Nhà nước cộng sản nguyên thủy", "b": "Nhà nước phong kiến", "c": "Nhà nước chủ nô", "d": "Nhà nước tư sản", "ans": "c"}, {"num": 11, "q": "Quyền hành pháp được hiểu là?", "a": "Quyền ban hành và triển khai thực hiện pháp luật", "b": "Quyền ban hành pháp luật", "c": "Quyền tổ chức thực hiện pháp luật", "d": "Quyền bảo vệ pháp luật", "ans": "c"}, {"num": 12, "q": "Tổ chức nào có quyền phân chia lãnh thổ thành các đơn vị hành chính?", "a": "Đảng cộng sản", "b": "Mặt trận Tổ quốc", "c": "Công đoàn", "d": "Nhà nước", "ans": "d"}, {"num": 13, "q": "Kiểu nhà nước mà trong đó giai cấp thống trị chiếm đa số trong xã hội là…", "a": "Chủ nô", "b": "Phong kiến", "c": "Tư sản", "d": "Xã hội chủ nghĩa", "ans": "d"}, {"num": 14, "q": "Cách thức và trình tự thành lập ra các cơ quan quyền lực tối cao của nhà nước, đó là", "a": "Hình thức chính thể", "b": "Hình thức cấu trúc nhà nước", "c": "Chế độ chính trị", "d": "Hình thức nhà nước", "ans": "a"}, {"num": 15, "q": "Người ở độ tuổi phải chịu trách nhiệm hình sự về tội phạm rất nghiêm trọng do cố ý hoặc tội phạm đặc biệt nghiêm trọng là…", "a": "từ đủ 14 đến dưới 16", "b": "từ 14 đến đủ 16", "c": "từ đủ 16 đến dưới 18", "d": "từ 16 đến đủ 18", "ans": "a"}, {"num": 16, "q": "Trách nhiệm pháp lý được áp dụng đối với người vi phạm pháp luật nhằm…", "a": "giáo dục, răn đe, hành hạ", "b": "buộc chủ thể vi phạm pháp luật chấm dứt hành vi trái pháp luật", "c": "xử phạt hành chính", "d": "phạt tù hoặc tử hình", "ans": "b"}, {"num": 17, "q": "Vi phạm pháp luật hành chính là hành vi vi phạm pháp luật, xâm phạm tới…", "a": "quan hệ xã hội và quan hệ kinh tế", "b": "các quy tắc quản lý nhà nước", "c": "các điều luật và các quan hệ hành chính", "d": "quan hệ xã hội và quan hệ hành chính", "ans": "b"}, {"num": 18, "q": "Nhà nước nào sau đây có chính thể cộng hòa đại nghị?", "a": "Đức", "b": "Bồ Đào Nha", "c": "Hoa Kỳ", "d": "Việt Nam", "ans": "a"}, {"num": 19, "q": "Nhà nước quân chủ hạn chế (quân chủ lập hiến) là nhà nước…? theo phương thức thừa kế thức thừa kế và một cơ quan nhà nước khác", "a": "Quyền lực nhà nước tối cao thuộc về một cơ quan tập thể và được hình thành", "b": "Quyền lực nhà nước tối cao thuộc về một cơ quan tập thể do bầu cử mà ra", "c": "Quyền lực nhà nước được phân chia cho người đứng đầu nhà nước theo phương", "d": "Quyền lực nhà nước thuộc về một tập thể gồm những người quý tộc và được hình thành do thừa kế", "ans": "c"}, {"num": 20, "q": "Trong nhà nước quân chủ chuyên chế thì…", "a": "Quyền lực nhà nước tối cao thuộc về một một cơ quan tập thể và do bầu cử mà ra", "b": "Quyền lực nhà nước tối cao thuộc về một người và được hình thành do bầu cử", "c": "Quyền lực nhà nước thuộc về một người và được hình thành theo phương thức thừa kế", "d": "Quyền lực nhà nước thuộc về một tập thể, được hình thành theo phương thức thừa kế", "ans": "c"}, {"num": 21, "q": "Nhà nước quân chủ là nhà nước…", "a": "Quyền lực nhà nước tối cao tập trung vào người đứng đầu nhà nước và được hình thành do bầu cử", "b": "Quyền lực nhà nước tối cao thuộc về người đứng đầu nhà nước hay thuộc về một tập thể, và được hình thành do bầu cử", "c": "Quyền lực nhà nước tối cao tập trung toàn bộ hay một phần chủ yếu vào tay người đứng đầu nhà nước theo nguyên tắc thừa kế", "d": "Tất cả đều sai", "ans": "c"}, {"num": 22, "q": "Hình thức cấu trúc nhà nước đơn nhất có đặc điểm…", "a": "Một hệ thống pháp luật", "b": "Hai hệ thống cơ quan Nhà nước", "c": "Lãnh thổ có chủ quyền riêng", "d": "Hai hệ thống pháp luật", "ans": "a"}, {"num": 23, "q": "Khi nghiên cứu về tổ chức thị tộc thì khẳng định nào sau đây là đúng?", "a": "Thị tộc là nhà nước trong xã hội Cộng sản nguyên thủy", "b": "Trong thị tộc đã có sự phân công lao động chuyên môn hóa ngành nghề", "c": "Thị tộc là đơn vị kinh tế đầu tiên của xã hội cộng sản nguyên thủy", "d": "Tổ chức thị tộc gắn liền xã hội có giai cấp", "ans": "c"}, {"num": 24, "q": "Chọn phương án đúng nhất: Tính giai cấp của nhà nước thể hiện ở phương diện nào?", "a": "kinh tế, chính trị, xã hội", "b": "kinh tế, chính trị, tư tưởng", "c": "kinh tế, văn hóa, xã hội.", "d": "kinh tế, chính trị, văn hóa", "ans": "b"}, {"num": 25, "q": "Chọn phương án đúng nhất: Pháp luật là…", "a": "các quy tắc xử sự chung, do nhà nước ban hành hoặc thừa nhận", "b": "các hệ thống chuẩn mực, được quy định trong Hiến pháp, do Nhà nước thừa nhận", "c": "các quy tắc xử sự chung, do nhà nước thừa nhận trên những chuẩn mực của đời sống", "d": "các quy tắc xử sự chung của mọi người, do nhà nước ban hành, được áp dụng ở phạm vi nhất định", "ans": "a"}, {"num": 26, "q": "Theo quan điểm của chủ nghĩa Mác - Lênin về nhà nước thì…", "a": "Nhà nước là hiện tượng tự nhiên", "b": "Nhà nước là hiện tượng xã hội mang tính lịch sử", "c": "Nhà nước là hiện tượng xã hội tồn tại vĩnh viễn", "d": "Nhà nước là hiện tượng xuất hiện và tồn tại cùng với sự xuất hiện, tồn tại của lịch sử xã hội loài người", "ans": "b"}, {"num": 27, "q": "Hành vi vi phạm các quy tắc, quy chế được xác lập trong một tổ chức, cơ quan, đơn vị là…", "a": "vi phạm hành chính", "b": "vi phạm dân sự", "c": "vi phạm kỷ luật", "d": "vi phạm hình sự", "ans": "c"}, {"num": 28, "q": "Hình phạt trong pháp luật hình sự của các nước thể hiện “hậu quả pháp lý” nặng nề nhất mà chủ thể phải gánh chịu do hành vi vi phạm pháp luật gây ra thể hiện đặc trưng…", "a": "Tính xác định chặt chẽ về mặt hình thức", "b": "Tính quyền lực, bắt buộc chung", "c": "Tính chủ quan, quy phạm phổ biến", "d": "Tính ý chí chủ quan", "ans": "b"}, {"num": 29, "q": "Chọn phương án đúng nhất: Bản chất của pháp luật Việt Nam thể hiện ở…", "a": "Tính giai cấp và tính xã hội", "b": "Tính giai cấp và tính chính trị", "c": "Tính xã hội và tính kinh tế", "d": "Tính kinh tế và tính xã hội", "ans": "a"}, {"num": 30, "q": "Pháp luật mang bản chất của xã hội vì…", "a": "pháp luật là cơ sở đảm bảo an toàn trật tự xã hội", "b": "pháp luật bắt nguồn từ thực tiễn đời sống xã hội", "c": "pháp luật góp phần hoàn chỉnh hệ thống xã hội", "d": "pháp luật đem đến một hệ thống chính trị hoàn chỉnh", "ans": "b"}, {"num": 31, "q": "Khi giải thích về nguồn gốc nhà nước, xem nhà nước là hiện tượng siêu nhiên, vĩnh cửu, đó là quan điểm của…", "a": "Thuyết Thần học", "b": "Thuyết Gia trưởng", "c": "Thuyết Khế ước xã hội", "d": "Thuyết Bạo lực", "ans": "a"}, {"num": 32, "q": "Khi nghiên cứu về tổ chức thị tộc thì khẳng định nào sau đây là SAI?", "a": "Thị tộc là đơn vị kinh tế đầu tiên của xã hội cộng sản nguyên thủy", "b": "Trong thị tộc đã hình thành hội đồng thị tộc", "c": "Trong thị tộc đã hình thành các giai cấp khác nhau", "d": "Thị tộc tồn tại gắn liền với nền kinh tế tự nhiên", "ans": "c"}, {"num": 33, "q": "Chọn phương án đúng nhất: Những quy phạm xã hội tồn tại trong xã hội cộng sản nguyên thủy là?", "a": "Đạo đức, tập quán, pháp luật", "b": "Tập quán, tín điều tôn giáo, luật pháp", "c": "Tín điều tôn giáo, tập quán pháp", "d": "Đạo đức, tập quán, tín điều tôn giáo", "ans": "d"}, {"num": 34, "q": "Hình thức chính thể nào sau đây không tồn tại chức danh Thủ tướng", "a": "Cộng hòa đại nghị", "b": "Quân chủ lập hiến", "c": "Cộng hòa Tổng thống", "d": "Cộng hòa lưỡng tính (hỗn hợp)", "ans": "c"}, {"num": 35, "q": "Hình thức chính thể cộng hòa dân chủ nhân dân là hình thức chính thể của quốc gia nào sau đây?", "a": "Việt Nam", "b": "Pháp", "c": "Đức", "d": "Nhật", "ans": "a"}, {"num": 36, "q": "Chọn phương án đúng nhất: Nhà nước Việt Nam đại diện cho lợi ích của…", "a": "giai cấp công nhân và nhân dân lao động", "b": "giai cấp công dân", "c": "các tầng lớp bị áp bức", "d": "nhân dân lao động", "ans": "a"}, {"num": 37, "q": "Con cái chửi, mắng cha, mẹ thì sẽ bị…", "a": "dư luận lên án", "b": "vi phạm pháp luật hành chính", "c": "vi phạm pháp luật dân sự", "d": "vi phạm pháp luật hình sự", "ans": "a"}, {"num": 38, "q": "Hình thức cấu trúc của Nhà nước Việt Nam là…", "a": "Từ đủ 15 tuổi", "b": "Từ đủ 18 tuổi", "c": "Từ đủ 21 tuổi", "d": "Từ đủ 25 tuổi", "ans": "a"}, {"num": 39, "q": "Quy định pháp luật về bầu cử của Việt Nam, ngoài các điều kiện khác, muốn tham gia ứng cử phải…", "a": "Từ đủ 15 tuổi", "b": "Từ đủ 18 tuổi", "c": "Từ đủ 21 tuổi", "d": "Từ đủ 25 tuổi", "ans": "c"}, {"num": 40, "q": "Chọn phương án đúng nhất: Kiểu nhà nước nào sử dụng phương pháp thuyết phục là chủ yếu để cai trị và quản lý xã hội:", "a": "Nhà nước XHCN", "b": "Nhà nước tư sản", "c": "Nhà nước phong kiến", "d": "Nhà nước chủ nô", "ans": "a"}, {"num": 41, "q": "Văn bản nào sau đây có hiệu lực cao nhất trong hệ thống pháp luật của Việt Nam?", "a": "Pháp lệnh", "b": "Luật", "c": "Hiến pháp", "d": "Nghị quyết", "ans": "c"}, {"num": 42, "q": "Chức năng nào dưới đây KHÔNG phải là chức năng chính của Quốc hội?", "a": "Chức năng lập pháp", "b": "Chức năng giám sát tối cao", "c": "Chức năng quyết định các vấn đề quan trọng của đất nước", "d": "Chức năng công tố", "ans": "d"}, {"num": 43, "q": "Ở Việt Nam, cơ quan thường trực của Quốc hội là:", "a": "Chính phủ", "b": "Uỷ ban thường vụ Quốc hội", "c": "Hội đồng nhân dân các cấp", "d": "Uỷ ban nhân dân các cấp", "ans": "b"}, {"num": 44, "q": "Nhận định nào SAI khi nói về vai trò của pháp luật?", "a": "Pháp luật là cơ sở để thiết lập, củng cố và tăng cường quyền lực nhà nước", "b": "Pháp luật là phương tiện để nhà nước quản lí kinh tế, xã hội", "c": "Pháp luật tạo ra môi trường ổn định cho việc thiết lập mối quan hệ giữa các nước", "d": "Pháp luật là phương tiện để nhân dân bảo vệ quyền chính đáng của mình", "ans": "c"}, {"num": 45, "q": "Chọn phương án đúng nhất: Pháp luật là…", "a": "Hệ thống các văn bản và nghị định do các cấp ban hành và thực hiện", "b": "Những luật và điều luật cụ thể trong thực tế đời sống", "c": "Hệ thống các quy tắc xử sự chung do nhà nước ban hành và được bảo đảm thực hiện bằng quyền lực nhà nước", "d": "Hệ thống các quy tắc xử sự được hình thành theo điều kiện cụ thể của từng địa phương", "ans": "c"}, {"num": 46, "q": "Trong Tuyên ngôn của Đảng Cộng sản, C.Mác và Ph.Ăngghen đã viết: “Pháp luật của các ông chỉ là ý chí của giai cấp các ông được đề lên thành luật, cái ý chí mà nội dung là dôon gc”á ctr ođniềgu c kâiuệ nn ósiin thrê hno mạtu vốậnt cchhỉấ at ic?ủ a giai cấp các ông quyết định”. Đại từ nhân xưng “các", "a": "Các nhà làm luật", "b": "Quốc hội, nghị viện", "c": "Nhà nước, giai cấp thống trị", "d": "Chính phủ", "ans": "c"}, {"num": 47, "q": "Ưu thế vượt trội của pháp luật so với các quy phạm xã hội khác là?", "a": "Tính cưỡng chế", "b": "Tính rộng rãi", "c": "Tính xã hội", "d": "Tồn tại trong thời gian dài", "ans": "a"}, {"num": 48, "q": "Cơ quan nào sau đây có thẩm quyền quyết định việc chia, tách đơn vị hành chính cấp tỉnh?", "a": "Quốc hội", "b": "Chính phủ", "c": "Chủ tịch nước", "d": "Bộ Chính trị", "ans": "a"}, {"num": 49, "q": "Pháp luật có đặc điểm là…", "a": "Bắt nguồn từ thực tiễn đời sống xã hội", "b": "Vì sự phát triển của xã hội", "c": "Pháp luật có tính quy phạm phổ biến; mang tính quyền lực, bắt buộc chung; có tính xác định chặt chẽ về mặt hình thức", "d": "Mang bản chất giai cấp và bản chất xã hội", "ans": "c"}, {"num": 50, "q": "Bản chất xã hội của pháp luật thể hiện ở…", "a": "Pháp luật được ban hành vì sự phát triển của xã hội", "b": "Pháp luật phản ánh những nhu cầu, lợi ích của các tầng lớp trong xã hội", "c": "Pháp luật bảo vệ quyền tự do, dân chủ rộng rãi cho nhân dân lao động", "d": "Pháp luật bắt nguồn từ xã hội, do các thành viên của xã hội thực hiện, vì sự phát triển của xã hội", "ans": "d"}, {"num": 51, "q": "Nội dung cơ bản của pháp luật bao gồm…", "a": "Các chuẩn mực thuộc về đời sống tinh thần, tình cảm của con người", "b": "Quy định các hành vi không được làm", "c": "Quy định các bổn phận của công dân", "d": "Các quy tắc xử sự (việc được làm, việc phải làm, việc không được làm)", "ans": "d"}, {"num": 52, "q": "Trong các quan điểm phi mácxít về nguồn gốc nhà nước thì quan điểm nào được coi là tiến bộ nhất?", "a": "Quan điểm của thuyết Thần học", "b": "Quan điểm của thuyết Gia trưởng", "c": "Quan điểm của thuyết Khế ước xã hội", "d": "Quan điểm của thuyết Bạo lực", "ans": "c"}, {"num": 53, "q": "Điền từ vào chỗ trống: C.Mác và Ph.Ăngghen đã khái quát hóa quá trình tồn tại, phát triển, thay đổi của xã hội loài người trong thời đại nguyên thủy trải qua..... lần phân công lao động?", "a": "Hai", "b": "Ba", "c": "Bốn", "d": "Năm", "ans": "b"}, {"num": 54, "q": "Ở Việt Nam, cơ quan nào sau đây có thẩm quyền quyết định đại xá?", "a": "Quốc hội", "b": "Chính phủ", "c": "Chủ tịch nước", "d": "Thủ tướng Chính phủ", "ans": "a"}, {"num": 55, "q": "Pháp luật công khai quy định về chế độ bóc lột nô lệ, thể hiện sự bất bình đẳng giữa chủ nô và nô lệ, đây là đặc điểm của kiểu pháp luật nào?", "a": "Pháp luật xã hội chủ nghĩa", "b": "Pháp luật phong kiến", "c": "Pháp luật tư sản", "d": "Pháp luật chủ nô", "ans": "d"}, {"num": 56, "q": "Nhà nước ban hành luật giao thông đường bộ và bắt buộc tất cả mọi người phải tuân theo, không được làm trái. Thể hiện đặc trưng…?", "a": "Tính quy phạm, phổ biến", "b": "Tính quy định, bắt buộc chung", "c": "Tính xác định chặt chẽ về mặt hình thức", "d": "Tính nhân dân", "ans": "b"}, {"num": 57, "q": "Pháp luật là công cụ bảo vệ lợi ích của….?", "a": "Tổ chức tôn giáo", "b": "Giai cấp thống trị", "c": "Nhà nước và xã hội", "d": "Nhân dân", "ans": "b"}, {"num": 58, "q": "Tính quy phạm phổ biến là đặc tính của:", "a": "Pháp luật", "b": "Đạo đức", "c": "Tôn giáo", "d": "Tổ chức xã hội", "ans": "a"}, {"num": 59, "q": "Hình thức pháp luật chủ yếu được áp dụng ở Việt Nam hiện nay là:", "a": "Văn bản quy phạm pháp luật", "b": "Tập quán pháp", "c": "Án lệ pháp", "d": "Tiền lệ pháp", "ans": "a"}, {"num": 60, "q": "Pháp luật phát sinh và tồn tại trong xã hội:", "a": "Có nhà nước", "b": "Không có giai cấp", "c": "Không có nhà nước", "d": "Nguyên thủy", "ans": "a"}, {"num": 61, "q": "Pháp luật có thể tác động vào kinh tế theo xu hướng:", "a": "Tác động tiêu cực", "b": "Tác động tích cực", "c": "Tích cực hoặc tiêu cực", "d": "Tất cả đều sai", "ans": "c"}, {"num": 62, "q": "Pháp luật ghi nhận các quan hệ xã hội chủ yếu và xác định quyền, nghĩa vụ pháp lý của các chủ thể trong quan hệ đó, thể hiện?", "a": "Chức năng của pháp luật", "b": "Chức năng điều chỉnh các quan hệ xã hội của pháp luật", "c": "Chức năng giáo dục của pháp luật", "d": "Nhiệm vụ của pháp luật", "ans": "b"}, {"num": 63, "q": "Đề cập đến quá trình phát triển, thay đổi của xã hội loài người, nhận định nào sau đây là SAI?", "a": "Lần phân công lao động thứ nhất: ngành chăn nuôi ra đời", "b": "Lần phân công lao động thứ hai: ngành tiểu thủ công nghiệp ra đời", "c": "Lần phân công lao động thứ ba: ngành thương nghiệp ra đời", "d": "Lần phân công lao động thứ tư: Nhà nước ra đời", "ans": "d"}, {"num": 64, "q": "Pháp luật quy định đẳng cấp trong xã hội và đặc quyền, đặc lợi của địa chủ phong kiến. Đây là đặc trưng của kiểu pháp luật nào?", "a": "Pháp luật chủ nô", "b": "Pháp luật XHCN", "c": "Pháp luật tư sản", "d": "Pháp luật phong kiến", "ans": "d"}, {"num": 65, "q": "Nội dung nào sau đây phù hợp với tính quy phạm và phổ biến của pháp luật?", "a": "Phạm vi tác động của quy phạm xã hội rộng hơn so với pháp luật", "b": "Ai cũng cần phải thực hiện theo các tín điều tôn giáo được ban hành", "c": "Cơ quan có quyền ban hành pháp luật thì cũng có quyền không thực hiện pháp luật", "d": "Phạm vi tác động của pháp luật rộng lớn cả về không gian, thời gian và đối tượng áp dụng", "ans": "d"}, {"num": 66, "q": "Ưu thế vượt trội của pháp luật so với các quy phạm xã hội khác là?", "a": "Tính cưỡng chế", "b": "Tính rộng rãi", "c": "Tính xã hội", "d": "Tồn tại trong thời gian dài", "ans": "a"}, {"num": 67, "q": "Chọn phương án đúng nhất: Hình thức nhà nước thừa nhận một số tập quán lưu truyền trong xã hội và quy định thành cách xử sự chung là hình thức pháp luật nào sau đây?", "a": "Tập quán pháp", "b": "Văn bản quy phạm pháp luật", "c": "Tiền lệ pháp", "d": "Tiền lệ pháp và tập quán pháp", "ans": "a"}, {"num": 68, "q": "Điền vào chỗ trống, Hồ Chí Minh: “Pháp luật của ta là pháp luật thật sự dân chủ vì nó bảo vệ....... rộng rãi cho nhân dân lao động”.", "a": "Lợi ích chính đáng", "b": "Quyền và nghĩa vụ", "c": "Quyền tự do, dân chủ", "d": "Quyền và nghĩa vụ cơ bản", "ans": "c"}, {"num": 69, "q": "Bản chất giai cấp của Pháp luật Việt Nam là…", "a": "Đảm bảo lợi ích của giai cấp công nhân và nhân dân lao động Việt Nam", "b": "Đảm bảo lợi ích của giai cấp lãnh đạo, nhưng giai cấp công nhân và nông dân được tự do dân chủ", "c": "Pháp luật là điều kiện để nhà nước ràng buộc mọi công dân", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 70, "q": "Quy phạm pháp luật là những quy tắc xử sự mang tính bắt buộc thể hiện ý chí của:", "a": "Nhà nước", "b": "Tổ chức xã hội", "c": "Tổ chức chính trị - xã hội", "d": "Tổ chức kinh tế", "ans": "a"}, {"num": 71, "q": "Nhận định nào sau đây là SAI?", "a": "Tập quán pháp là hình thức Nhà nước thừa nhận một số tập quán lưu truyền trong xã hội và quy định thành cách xử sự chung, được Nhà nước bảo đảm thực hiện", "b": "Hình thức tập quán pháp được sử dụng nhiều trong Nhà nước xã hội chủ nghĩa", "c": "Văn bản quy phạm pháp luật là hình thức pháp luật tiến bộ nhất", "d": "Hình thức tiền lệ pháp còn gọi là án lệ pháp", "ans": "b"}, {"num": 72, "q": "Trong các hành vi sau đây, hành vi nào phải chịu trách nhiệm về mặt hình sự?", "a": "Vượt đèn đỏ, gây tai nạn chết người", "b": "Đi ngược chiều", "c": "Tụ tập và gây gối trật tự công cộng", "d": "Cắt trộm cáp điện", "ans": "a"}, {"num": 73, "q": "Nghị định là văn bản quy phạm pháp luật do cơ quan Nhà nước có thẩm quyền ban hành là:", "a": "Chính phủ", "b": "Uỷ ban thường vụ quốc hội", "c": "Thủ tướng chính phủ", "d": "Chủ tịch nước", "ans": "a"}, {"num": 74, "q": "Bộ phận nào của quy phạm pháp luật nêu lên cách thức xử sự cho chủ thể được làm, không được làm, phải làm:", "a": "Giả định", "b": "Quy định", "c": "Chế tài", "d": "Tất cả đều sai", "ans": "b"}, {"num": 75, "q": "Trong các nghĩa vụ sau đây nghĩa vụ nào KHÔNG phải là nghĩa vụ pháp lý?", "a": "Đoàn viên thanh niên phải chấp hành điều lệ của Đoàn", "b": "Người kinh doanh phải thực hiện nghĩa vụ nộp thuế", "c": "Thanh niên đủ 18 tuổi phải thực hiện nghĩa vụ quân sự", "d": "Con cái có nghĩa vụ phụng dưỡng cha mẹ già", "ans": "a"}, {"num": 76, "q": "Hình thức pháp luật này ngày càng được sử dụng rộng rãi ở các quốc gia vì nó khắc phục được những hạn chế của các hình thức pháp luật khác và có tính rõ ràng, cụ thể, được ban hành theo trình tự, thủ tục nhất định, đó là?", "a": "Tiền lệ pháp", "b": "Tập quán pháp", "c": "Văn bản luật", "d": "Văn bản quy phạm pháp luật", "ans": "d"}, {"num": 77, "q": "Anh A lái xe máy và lưu thông đúng luật. Chị B đi xe đạp không quan sát và bất ngờ băng ngang qua đường làm anh A bị thương (giám định là 10%). Theo bạn trường hợp này xử phạt như thế nào?", "a": "Cảnh cáo và buộc chị B phải bồi thường thiệt hại cho gia đình anh A", "b": "Cảnh cáo phạt tiền chị B", "c": "Không xử lý chị B vì chị B là người đi xe đạp", "d": "Phạt tù chị B", "ans": "a"}, {"num": 78, "q": "Chọn phương án đúng nhất: Một trong những đặc điểm để phân biệt pháp luật với quy phạm đạo đức là:", "a": "Pháp luật có tính quyền lực, bắt buộc chung", "b": "Pháp luật có tính quyền lực", "c": "Pháp luật có tính bắt buộc chung", "d": "Pháp luật có tính quy phạm", "ans": "a"}, {"num": 79, "q": "Pháp luật là phương tiện để công dân:", "a": "Sống tự do, dân chủ", "b": "Thực hiện và bảo vệ quyền, lợi ích hợp pháp của mình", "c": "Quyền con người được tôn trọng và bảo vệ", "d": "Công dân phát triển toàn diện", "ans": "b"}, {"num": 80, "q": "Quản lí bằng pháp luật là phương pháp quản lí…", "a": "hữu hiệu và phức tạp nhất.", "b": "dân chủ và hiệu quả nhất", "c": "hiệu quả và khó khăn nhất", "d": "dân chủ và cứng rắn nhất", "ans": "b"}, {"num": 81, "q": "Bộ phận đảm bảo cho quy phạm pháp luật được thực hiện nghiêm chỉnh là…?", "a": "Quy định", "b": "Giả định", "c": "Chế tài", "d": "Quy cách", "ans": "c"}, {"num": 82, "q": "Thời điểm năng lực pháp lụât và năng lực hành vi của pháp nhân được nhà nước công nhận là:", "a": "Cùng một thời điểm", "b": "Năng lực pháp luật được công nhận trước năng lực hành vi", "c": "Năng lực hành vi được công nhận trước năng lực pháp luật", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 83, "q": "Nội dung của quan hệ pháp luật là:", "a": "Quyền và nghĩa vụ của các chủ thể trong quan hệ pháp luật", "b": "Những giá trị mà các chủ thể quan hệ pháp luật muốn đạt được", "c": "Là các bên tham gia vào quan hệ pháp luật", "d": "Là đối tượng mà các chủ thể quan tâm khi tham gia vào quan hệ pháp luật", "ans": "a"}, {"num": 84, "q": "Khi nào pháp nhân có năng lực chủ thể:", "a": "Khi nhà nước cho phép hoặc công nhận sự thành lập của pháp nhân", "b": "Khi tổ chức có đủ số thành viên", "c": "Khi các thành viên thỏa thuận thành lập pháp nhân", "d": "Khi một tổ chức có đủ vốn", "ans": "a"}, {"num": 85, "q": "Khả năng của chủ thể bằng chính hành vi của mình thực hiện được các quyền và nghĩa vụ mà pháp luật quy định, đó là:", "a": "Năng lực pháp luật", "b": "Năng lực hành vi", "c": "Năng lực chủ thể", "d": "Tất cả đều đúng", "ans": "b"}, {"num": 86, "q": "Điền từ vào chỗ trống: Pháp luật là hệ thống các quy tắc xử sự chung do ……… ban hành và đảm bảo thực hiện bằng quyền lực nhà nước.", "a": "Đảng", "b": "Chính phủ", "c": "Tổ chức xã hội", "d": "Nhà nước", "ans": "d"}, {"num": 87, "q": "Các quy tắc xử sự (việc được làm, việc phải làm, việc không được làm) thể hiện vấn đề nào của pháp luật?", "a": "Phương thức tác động", "b": "Nội dung", "c": "Nguồn gốc", "d": "Hình thức thể hiện", "ans": "a"}, {"num": 88, "q": "Chọn phương án đúng nhất: Nhà nước Việt Nam điều hành đất nước bằng…", "a": "Văn hoá, giáo dục, chính trị", "b": "Kế hoạch phát triển kinh tế", "c": "Quân đội và chính quyền", "d": "Hiến pháp và pháp luật", "ans": "d"}, {"num": 89, "q": "Tiêu chuẩn xác định một hệ thống pháp luật hoàn thiện là?", "a": "Tính toàn diện, tính đồng bộ", "b": "Tính phù hợp", "c": "Trình độ kỹ thuật pháp lý cao", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 90, "q": "Chọn phương án đúng nhất: Năng lực hành vi của cá nhân chỉ xuất hiện khi?", "a": "Cá nhân đủ 18 tuổi, không mắc bệnh tâm thần", "b": "Cá nhân đủ 16 tuổi, có trí óc bình thường", "c": "Cá nhân đã đến độ tuổi nhất định và có những điều kiện nhất định", "d": "Được nhà nước quy định", "ans": "c"}, {"num": 91, "q": "Một tổ chức có tư cách pháp nhân khi có điều kiện?", "a": "Được thành lập hợp pháp, có cơ cấu tổ chức chặt chẽ", "b": "Có tài sản độc lập với cá nhân, tổ chức khác", "c": "Nhân danh mình tham gia các quan hệ pháp luật một cách độc lập", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 92, "q": "Các quy phạm pháp luật bắt nguồn từ đâu?", "a": "Từ tư duy trừu tượng của con người", "b": "Từ quyền lực của giai cấp thống trị", "c": "Từ thực tiễn đời sống xã hội, do thực tiễn cuộc sống đòi hỏi", "d": "Từ ý thức của các cá nhân trong xã hội", "ans": "c"}, {"num": 93, "q": "“Pháp luật là của ai, do ai và vì ai?” Đề cập đến vấn đề nào của pháp luật?", "a": "Nội dung của pháp luật.", "b": "Hình thức thể hiện của pháp luật", "c": "Khái niệm cơ bản của pháp luật.", "d": "Bản chất của pháp luật", "ans": "d"}, {"num": 94, "q": "Cá nhân có năng lực hành vi đầy đủ khi:", "a": "Từ đủ 15 tuổi trở lên", "b": "Từ đủ 21 tuổi trở lên", "c": "Từ đủ 18 tuổi trở lên", "d": "Từ đủ 6 tuổi trở lên", "ans": "c"}, {"num": 95, "q": "Quan hệ xã hội nào sau đây không phải là quan hệ pháp luật?", "a": "Quan hệ vợ – chồng", "b": "Quan hệ mua – bán", "c": "Quan hệ cha mẹ – con", "d": "Quan hệ tình yêu nam – nữ", "ans": "d"}, {"num": 96, "q": "Tổ chức được thành lập hợp pháp được gọi là:", "a": "Pháp nhân", "b": "Thể nhân", "c": "Cá nhân", "d": "Tất cả đều sai", "ans": "a"}, {"num": 97, "q": "Kết hôn là:", "a": "Hành vi pháp lý", "b": "Sự biến pháp lý", "c": "Sự kiện thông thường", "d": "Năng lực hành vi", "ans": "a"}, {"num": 98, "q": "Chủ thể thực hiện vi phạm hình sự có thể là…", "a": "Cá nhân có năng lực trách nhiệm hình sự", "b": "Tổ chức là pháp nhân", "c": "Tổ chức không là pháp nhân", "d": "Người tâm thần", "ans": "a"}, {"num": 99, "q": "Điền từ vào chỗ trống: “Pháp luật là hệ thống quy tắc xử sự mang tính ............., do............ ban hành và bảo đảm thực hiện, thể hiện ................. của giai cấp thống trị và phụ thuộc vào các điều kiện ..............., là nhân tố điều chỉnh các quan hệ xã hội”.", "a": "Bắt buộc – quốc hội – ý chí – chính trị", "b": "Bắt buộc chung – nhà nước – lý tưởng – chính trị", "c": "Bắt buộc – quốc hội – lý tưởng – kinh tế xã hội", "d": "Bắt buộc chung – nhà nước – ý chí – kinh tế xã hội", "ans": "d"}, {"num": 100, "q": "Chọn phương án đúng nhất: Nói đến vai trò của pháp luật đối với sự phát triển bền vững của đất nước là nói đến sự tác động của pháp luật đối với…", "a": "Các lĩnh vực của đời sống xã hội", "b": "Lĩnh vực bảo vệ môi trường", "c": "Việc xây dựng và bảo vệ đất nước", "d": "Phát triển kinh tế đất nước", "ans": "a"}, {"num": 101, "q": "Hành vi tổ chức đánh bạc của công chức, viên chức nhà nước bị công an bắt quả tang được xác định là hành vi:", "a": "Vi phạm hình sự", "b": "Vi phạm công vụ", "c": "Vi phạm kỷ luật", "d": "Vi phạm dân sự", "ans": "a"}, {"num": 102, "q": "Xác định phương án SAI: Khi phát sinh tranh chấp về quyền và nghĩa vụ giữa các chủ thể thì…", "a": "Các chủ thể không có quyền tự giải quyết tranh chấp", "b": "Các chủ thể có thể nhờ người hòa giải", "c": "Các chủ thể có thể thỏa thuận với nhau về cách giải quyết tranh chấp", "d": "Các chủ thể có quyền yêu cầu nhà nước giải quyết", "ans": "a"}, {"num": 103, "q": "Lịch sử xã hội loài người đã và đang trải qua mấy kiểu pháp luật?", "a": "2 kiểu pháp luật", "b": "4 kiểu pháp luật", "c": "5 kiểu pháp luật", "d": "6 kiểu pháp luật", "ans": "b"}, {"num": 104, "q": "Ông B tổ chức buôn ma túy, hỏi ông B phải chịu trách nhiệm pháp lý nào?", "a": "Trách nhiệm hành chính", "b": "Trách nhiệm hình sự", "c": "Trách nhiệm dân sự", "d": "Trách nhiệm kỷ luật", "ans": "b"}, {"num": 105, "q": "Chế tài nào sau đây chỉ do Tòa án áp dụng:", "a": "Chế tài hành chính", "b": "Chế tài hình sự", "c": "Chế tài kỷ luật", "d": "Chế tài công vụ", "ans": "b"}, {"num": 106, "q": "Bồi thường thiệt hại là chế tài:", "a": "Dân sự", "b": "Hình sự", "c": "Hành chính", "d": "Kỷ luật", "ans": "a"}, {"num": 107, "q": "Điền vào chỗ trống: Chủ thể vi phạm pháp luật là cá nhân hoặc tổ chức có ...... đã thực hiện hành vi vi phạm pháp luật?", "a": "Khả năng", "b": "Năng lực hành vi", "c": "Năng lực trách nhiệm pháp lý", "d": "Năng lực pháp luật", "ans": "d"}, {"num": 108, "q": "Trường hợp nào sau đây thì mới được bắt, giam, giữ người", "a": "Bắt người khi đang bị tình nghi có hành vi vi phạm pháp luật", "b": "Bắt người phạm tội quả tang hoặc đang bị truy nã", "c": "Bắt, giam, giữ người khi người này đang nghiện ma tuý", "d": "Bắt giam người khi người này có người thân phạm pháp luật", "ans": "b"}, {"num": 109, "q": "Ở Việt Nam, cứ đến ngày Quốc khánh (2/9) người nào cải tạo tốt, biết hối cải thì được Chủ tịch nước ân xá cho ra tù trước thời hạn. Thể hiện bản chất nào của pháp luật?", "a": "Bản chất giai cấp", "b": "Bản chất xã hội", "c": "Bản chất nhân đạo sâu sắc pháp luật xã hội chủ nghĩa", "d": "Bản chất nhân dân", "ans": "c"}, {"num": 110, "q": "Chọn phương án đúng nhất: Phương thức tác động của nhà nước lên quan hệ pháp luật là…", "a": "giáo dục, thuyết phục và cưỡng chế", "b": "giáo dục, cưỡng chế", "c": "Cưỡng chế", "d": "giáo dục", "ans": "a"}, {"num": 111, "q": "Lệnh là văn bản quy phạm pháp luật do cơ quan nào sau đây ban hành?", "a": "Thủ tướng Chính phủ", "b": "Chủ tịch Quốc hội", "c": "Tổng Bí thư", "d": "Chủ tịch nước", "ans": "d"}, {"num": 112, "q": "Khẳng định nào SAI khi nghiên cứu về mặt chủ quan của vi phạm pháp luật?", "a": "Động cơ là cái thúc đẩy chủ thể thực hiện hành vi vi phạm pháp luật", "b": "Lỗi là một trong những căn cứ để xác định mức độ trách nhiệm pháp lý đối với chủ thể vi phạm pháp luật", "c": "Lỗi là thái độ tâm lý của chủ thể đối với hành vi trái pháp luật mà mình đã thực hiện và hậu quả do hành vi gây ra", "d": "Chỉ khi nào hành vi trái pháp luật được chủ thể thực hiện một cách cố ý thì mới có thể là hành vi vi phạm pháp luật", "ans": "d"}, {"num": 113, "q": "Những biểu hiện, diễn biến tâm lý bên trong của chủ thể vi phạm pháp luật gọi là?", "a": "Mặt chủ quan của vi phạm pháp luật", "b": "Nhận thức, thái độ của chủ thể", "c": "Chủ thể vi phạm pháp luật", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 114, "q": "Khi nghiên cứu về chủ thể quan hệ pháp luật thì khẳng định nào sau đây là đúng?", "a": "Tất cả mọi cá nhân đều có thể trở thành chủ thể của quan hệ pháp luật", "b": "Tất cả mọi tổ chức đều có thể trở thành chủ thể của quan hệ pháp luật", "c": "Tất cả mọi cá nhân và tổ chức có đủ những điều kiện do pháp luật quy định đều có thể trở thành chủ thể của quan hệ pháp luật", "d": "Tất cả các cơ quan, đơn vị, tổ chức và cá nhân trong xã hội đều có thể trở thành chủ thể của quan hệ pháp luật", "ans": "c"}, {"num": 115, "q": "A đánh B gây thương tích 15%, theo bạn, Bộ luật hình sự năm 2015 sửa đổi bổ sung năm 2017 thì A phải chịu hình phạt nào?", "a": "Răn đe, giáo dục", "b": "Bồi thường thiệt hại", "c": "Phạt tù", "d": "Tạm giữ để giáo dục", "ans": "c"}, {"num": 116, "q": "Các quyền và nghĩa vụ pháp lý cơ bản của công dân được qui định trong…", "a": "Luật hành chính", "b": "Luật hôn nhân - gia đình", "c": "Luật dân sự", "d": "Hiến pháp", "ans": "d"}, {"num": 117, "q": "Chủ thể có năng lực trách nhiệm pháp lý khi có đủ điều kiện sau?", "a": "Từ 18 tuổi trở lên và có trí óc bình thường", "b": "Đạt độ tuổi do pháp luật quy định, có năng lực pháp luật", "c": "Có năng lực pháp luật và năng lực hành vi", "d": "Đạt độ tuổi do pháp luật quy định, có khả năng nhận thức và điều khiển hành vi", "ans": "d"}, {"num": 118, "q": "Khi nghiên cứu về quyền chủ thể trong quan hệ pháp luật, thì khẳng định nào sau đây là ĐÚNG?", "a": "Khả năng được lựa chọn những xử sự theo ý muốn chủ quan của mình", "b": "Khả năng yêu cầu các chủ thể khác thực hiện nghĩa vụ để bảo đảm việc thực hiện quyền của mình", "c": "Khả năng yêu cầu cơ quan Nhà nước có thẩm quyền bảo vệ quyền của mình khi bị phía chủ thể bên kia vi phạm", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 119, "q": "Nhận định nào sau đây SAI khi nói đến vai trò của pháp luật…", "a": "Pháp luật là phương tiện để Nhà nước quản lý mọi mặt đời sống xã hội", "b": "Pháp luật là phương tiện thực hiện và bảo vệ quyền, lợi ích hợp pháp của mỗi công dân", "c": "Pháp luật là công cụ thực hiện đường lối chính sách của Đảng", "d": "Pháp luật là công cụ bảo vệ mọi quyền và lợi ích của mọi công dân", "ans": "d"}, {"num": 120, "q": "Nội dung nào sau đây phù hợp với tính quy phạm và phổ biến của pháp luật?", "a": "Phạm vi tác động của quy phạm xã hội rộng hơn so với pháp luật", "b": "Ai cũng cần phải thực hiện theo các tín điều tôn giáo được ban hành", "c": "Cơ quan có quyền ban hành pháp luật thì cũng có quyền không thực hiện pháp luật", "d": "Phạm vi tác động của pháp luật rộng lớn cả về không gian, thời gian và đối tượng áp dụng", "ans": "d"}, {"num": 121, "q": "Ưu thế vượt trội của pháp luật so với các quy phạm xã hội khác là?", "a": "Tính cưỡng chế", "b": "Tính rộng rãi", "c": "Tồn tại trong thời gian dài", "d": "Tính xã hội", "ans": "a"}, {"num": 122, "q": "Nghĩa vụ pháp lý của chủ thể gồm có?", "a": "Chủ thể phải tiến hành một số hành vi nhất định do pháp luật quy định", "b": "Chủ thể phải tự kiềm chế, không được thực hiện một số hành vi nhất định", "c": "Chủ thể phải chịu trách nhiệm pháp lý khi không thực hiện theo cách xử sự bắt buộc mà pháp luật đã quy định", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 123, "q": "Trong các yếu tố cấu thành hệ thống pháp luật, yếu tố được xem là đơn vị cơ bản nhỏ nhất trong hệ thống pháp luật là:", "a": "Quy phạm pháp luật", "b": "Chế định pháp luật", "c": "Ngành luật", "d": "Tất cả đếu đúng", "ans": "a"}, {"num": 124, "q": "Các quy phạm pháp luật có đặc điểm chung giống nhau để điều chỉnh một nhóm quan hệ xã hội tương ứng, đó chính là:", "a": "Quy phạm pháp luật", "b": "Chế định pháp luật", "c": "Ngành luật", "d": "Hệ thống pháp luật", "ans": "b"}, {"num": 125, "q": "Tổng hợp các quy phạm pháp luật điều chỉnh một lĩnh vực nhất định của đời sống xã hội, đó chính là:", "a": "Quy phạm pháp luật", "b": "Chế định pháp luật", "c": "Ngành luật", "d": "Hệ thống pháp luật", "ans": "c"}, {"num": 126, "q": "Chọn phương án đúng nhất: Pháp luật là công cụ bảo vệ lợi ích của…?", "a": "Tổ chức tôn giáo", "b": "Giai cấp thống trị", "c": "Nhà nước và xã hội", "d": "Nhân dân", "ans": "c"}, {"num": 127, "q": "Tính cưỡng chế của pháp luật được thể hiện:", "a": "Những hành vi vi phạm pháp luật đều bị xử phạt hành chính", "b": "Những hành vi vi phạm pháp luật đều bị áp dụng hình phạt", "c": "Những hành vi vi phạm pháp luật đều có thể bị áp dụng biện pháp chế tài", "d": "Những hành vi vi phạm pháp luật đều bị xử lý kỷ luật", "ans": "c"}, {"num": 128, "q": "Pháp luật và đạo đức là hai hiện tượng…", "a": "Đều mang tính quy phạm", "b": "Đều mang tính quy phạm bắt buộc chung", "c": "Đều là quy phạm tồn tại ở dạng thành văn", "d": "Đều do nhà nước đặt ra hoặc thừa nhận", "ans": "a"}, {"num": 129, "q": "Vi phạm hình sự ở mức độ tội phạm nghiêm trọng, khung hình cao nhất là…", "a": "7 năm", "b": "5 năm", "c": "3 năm", "d": "8 năm", "ans": "a"}, {"num": 130, "q": "Đạo luật nào dưới đây quy định một cách cơ bản về chế độ chính trị, chế độ kinh tế, văn hóa, xã hội và tổ chức bộ máy nhà nước.", "a": "Luật tổ chức Quốc hội", "b": "Luật tổ chức Chính phủ", "c": "Luật tổ chức Hội đồng nhân dân và UBND", "d": "Hiến pháp", "ans": "d"}, {"num": 131, "q": "Thừa kế là chế định quan trọng của ngành luật nào sau đây?", "a": "Luật Tố tụng dân sự", "b": "Luật Hình sự", "c": "Luật đất đai", "d": "Luật Dân sự", "ans": "d"}, {"num": 132, "q": "A và B đua xe, lạng lách đánh võng trên đường và bị cảnh sát giao thông xử lý. Theo em, A và B phải chịu trách nhiệm pháp lý nào?", "a": "Cảnh cáo, phạt tiền, giam xe", "b": "Cảnh cáo, phạt tiền", "c": "Cảnh cáo, giam xe", "d": "Phạt tiền, giam xe", "ans": "a"}, {"num": 133, "q": "Cảnh sát giao thông xử phạt người chở hang cồng kềnh khi tham gia giao thông là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "uân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 134, "q": "Các hình thức thực hiện pháp luật theo thứ tự là:", "a": "Sử dụng pháp luật, thi hành pháp luật, áp dụng pháp luật và tuân thủ pháp luật", "b": "Tuân thủ pháp luật, thi hành pháp luật, sử dụng pháp luật và áp dụng pháp luật", "c": "Sử dụng pháp luật, thi hành pháp luật, tuân thủ pháp luật và áp dụng pháp luật", "d": "Tuân thủ pháp luật, sử dụng pháp luật, thi hành pháp luật và áp dụng pháp luật", "ans": "b"}, {"num": 135, "q": "Các trường hợp chiếm hữu nào sau đây là chiếm hữu không có căn cứ pháp luật:", "a": "Chiếm hữu vật đánh rơi không khai báo", "b": "Chiếm hữu của chủ sở hữu vật", "c": "Chiếm hữu do chủ sở hữu vật uỷ quyền", "d": "Chiếm hữu thông qua việc thuê vật của chủ sở hữu", "ans": "a"}, {"num": 136, "q": "Các trường hợp quyền định đoạt tài sản của chủ sở hữu bị hạn chế:", "a": "Bán vật là di tích lịch sử", "b": "Bán vật đang thế chấp", "c": "Bán vật đang cầm cố", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 137, "q": "Chọn phương án đúng nhất: Hàng thừa kế thứ nhất theo quy định pháp luật về thừa kế:", "a": "Con nuôi của người chết", "b": "Con đẻ của người chết", "c": "Em ruột của người chết", "d": "Vợ, chồng, cha đẻ, mẹ đẻ, cha nuôi, mẹ nuôi, con đẻ, con nuôi của người chết", "ans": "d"}, {"num": 138, "q": "Hành vi không lạng lách, đánh võng khi đi xe máy trên đường của anh A là biểu hiện hình thức thự hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Tuân thủ pháp luật", "c": "Thi hành pháp luật", "d": "Áp dụng pháp luật", "ans": "b"}, {"num": 139, "q": "Ông B đi vào đường ngược chiều, chưa gây tai nạn cho ai nhưng cảnh sát giao thông đã xử phạt với việc xử phạt đó nhằm mục đích gì?", "a": "Ngăn chặn không để gây tai nạn cho chính ông B", "b": "Chấm dứt hành vi vi phạm pháp luật (đi ngược chiều)", "c": "Ngăn chặn không để gây tai nạn cho người khác", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 140, "q": "Trong các hành vi dưới đây hành vi nào thể hiện công dân sử dụng pháp luật?", "a": "Người kinh doanh trốn thế phải nộp phạt", "b": "Anh A và chị B đến UBND phường đăng ký kết hôn", "c": "Các bên tranh chấp phải thực hiện các quyền và nghĩa vụ của mình theo qui định của pháp luật", "d": "Công ty X thực hiện nghĩa vụ đóng thuế theo quy định pháp luật", "ans": "b"}, {"num": 141, "q": "Anh A sử dụng điện thoại di động khi đang điều khiển xe máy. Công an đã xử phạt hành chính anh A. Việc làm của công an là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Tuân thủ pháp luật", "b": "Sử dụng pháp luật", "c": "Thi hành pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 142, "q": "Thực hiện trách nhiệm pháp lý đối với người từ đủ 14 đến dưới 18 tuổi là…", "a": "Giáo dục, răn đe là chính", "b": "Có thể bị phạt tù", "c": "Buộc phải cách li với xã hội và không có điều kiện tái hòa nhập cộng đồng", "d": "Chủ yếu là đưa ra lời khuyên", "ans": "a"}, {"num": 143, "q": "Quan hệ xã hội nào dưới đây không phải là quan hệ pháp luật…", "a": "Anh A và chị B làm thủ tục đăng ký kết hôn", "b": "Chị G ra chợ mua rau", "c": "Quan hệ lao động", "d": "Quan hệ cha mẹ – con", "ans": "b"}, {"num": 144, "q": "Hành vi phạm tội nào sau đây không bị xem là tội phạm:", "a": "Không đăng ký tạm trú, tạm vắng", "b": "Trộm cắp tài sản công dân", "c": "Đua xe trái phép gây hậu quả nghiêm trọng", "d": "Lừa đảo chiếm đoạt tài sản", "ans": "a"}, {"num": 145, "q": "Tòa án huyện A tuyên bố bị cáo B mức phạt 2 năm tù vì tội hiếp dâm, là…", "a": "Sử dụng pháp luật", "b": "Áp dụng pháp luật", "c": "Thi hành pháp luật", "d": "Tuân thủ pháp luật", "ans": "b"}, {"num": 146, "q": "Các tổ chức, cá nhân chủ động thực hiện quyền (những việc được làm) là:", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 147, "q": "Các tổ chức cá nhân chủ động thực hiện nghĩa vụ (những việc phải làm) là…", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "b"}, {"num": 148, "q": "Độ tuổi tối thiểu chịu trách nhiệm hình sự là từ đủ:", "a": "12 tuổi", "b": "14 tuổi", "c": "16 tuổi", "d": "18 tuổi", "ans": "b"}, {"num": 149, "q": "Chọn phương án đúng nhất: Sự kiện pháp lý là những sự kiện xảy ra…?", "a": "Từ hành vi xử sự của con người", "b": "Từ thực tiễn đời sống xã hội", "c": "Trong thực tiễn đời sống mà sự xuất hiện hay mất đi của nó được pháp luật gắn với việc hình thành, thay đổi hay chấm dứt quan hệ pháp luật", "d": "Tất cả đều sai", "ans": "c"}, {"num": 150, "q": "Khi nghiên cứu về chủ thể quan hệ pháp luật thì khẳng định nào sau đây là đúng?", "a": "Mọi cá nhân đều có năng lực hành vi như nhau", "b": "Mọi cá nhân đạt độ tuổi do luật định được tham gia vào tất cả quan hệ pháp luật", "c": "Mọi tổ chức đều được tham gia vào tất cả quan hệ pháp luật", "d": "Mọi chủ thể tham gia vào quan hệ pháp luật đều có quyền và nghĩa vụ nhất định", "ans": "d"}, {"num": 151, "q": "Khi nghiên cứu về đặc điểm của quan hệ pháp luật thì khẳng định nào sau đây là sai?", "a": "Quan hệ pháp luật là loại quan hệ có ý chí", "b": "Quan hệ pháp luật xuất hiện dựa trên cơ sở quy phạm pháp luật", "c": "Quan hệ pháp luật do nhà nước quy định", "d": "Quan hệ pháp luật luôn gắn liền với sự kiện pháp lý", "ans": "c"}, {"num": 152, "q": "Các tổ chức cá nhân không làm những việc bị cấm là:", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "c"}, {"num": 153, "q": "Quyền lao động của công dân chỉ bắt đầu được thực hiện khi nào?", "a": "Phải có người có nhu cầu sử dụng lao động (thuê mướn)", "b": "Công dân phải tìm được vịêc làm", "c": "Người lao động và người sử dụng lao động xác lập một quan hệ pháp luật lao động cụ thể", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 154, "q": "Quá trình thực hiện pháp luật chỉ đạt hiệu quả khi các chủ thể tham gia quan hệ pháp luật thực hiện…", "a": "Đúng đắn các quyền của mình theo Hiến pháp và pháp luật", "b": "Đầy đủ các quyền và nghĩa vụ của mình theo Hiến pháp và pháp luật", "c": "Đầy đủ nghĩa vụ của mình theo Hiến pháp và pháp luật", "d": "Đúng đắn các quyền và nghĩa vụ của mình theo Hiến pháp và pháp luật", "ans": "d"}, {"num": 155, "q": "Xác định phương án SAI: Trong một quan hệ pháp luật…", "a": "Không có chủ thể nào chỉ có quyền mà không có nghĩa vụ", "b": "Quyền và nghĩa vụ của các chủ thể không tách rời nhau", "c": "Không có chủ thể nào chỉ có nghĩa vụ mà không có quyền", "d": "Quyền của cá nhân, tổ chức này không liên quan đến nghĩa vụ của cá nhân, tổ chức khác", "ans": "d"}, {"num": 156, "q": "Dấu hiệu cơ bản của vi phạm pháp luật là", "a": "Là hành vi trái pháp luật", "b": "Do người có năng lực trách nhiệm pháp lý thực hiện", "c": "Vi phạm pháp luật phải có lỗi", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 157, "q": "Nhà nước đưa ra trách nhiệm pháp lý là nhằm:", "a": "Phạt tiền người vi phạm", "b": "Buộc chủ thể vi phạm chấm dứt hành vi trái pháp luật, phải chịu những thiệt hại nhất định; giáo dục răn đe những người khác", "c": "Lập lại trật tự xã hội", "d": "Ngăn chặn người vi phạm có thể có vi phạm mới", "ans": "b"}, {"num": 158, "q": "Khả năng chủ thể có quyền hoặc có nghĩa vụ pháp lý do Nhà nước quy định, gọi là?", "a": "Khả năng pháp lý", "b": "Năng lực pháp luật", "c": "Năng lực hành vi", "d": "Năng lực đạo đức", "ans": "b"}, {"num": 159, "q": "Chọn phương án đúng nhất: Quan hệ pháp luật hình sự là:", "a": "Quan hệ phát sinh khi có hành vi phạm tội", "b": "Quan hệ phát sinh giữa người phạm tội với người bị hại", "c": "Quan hệ phát sinh giữa nhà nước và người phạm tội khi có một tội phạm xảy ra", "d": "Tất cả đều sai", "ans": "c"}, {"num": 160, "q": "Bạn A (17 tuổi) vì mâu thuẫn cá nhân với anh B (hàng xóm) nên đã rủ một bạn mang theo hung khí đến anh B, khiến anh B tử vong. Hành vi của bạn A thuộc loại vi phạm pháp luật nào dưới đây?", "a": "Vi phạm hình sự", "b": "Vi phạm dân sự", "c": "Vi phạm hành chính", "d": "Vi phạm kỉ luật", "ans": "a"}, {"num": 161, "q": "Các cá nhân, tổ chức sử dụng đúng đắn các quyền của mình, làm những gì mà pháp luật cho phép làm là nội dung của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 162, "q": "Nguyên nhân cốt lõi của sự ra đời nhà nước là:", "a": "Kết quả của ba lần phân công lao động trong lịch sử", "b": "Kết quả của nền sản xuất hàng hoá cùng những hoạt động thương nghiệp", "c": "Nhu cầu về sự cần thiết phải có một tổ chức để dập tắt xung đột giai cấp", "d": "Nhu cầu về sự cần thiết phải có một tổ chức thay thế thị tộc - bộ lạc", "ans": "c"}, {"num": 163, "q": "Tính giai cấp của nhà nước thể hiện ở chỗ:", "a": "Nhà nước là một bộ máy trấn áp giai cấp", "b": "Nhà nước là một bộ máy của giai cấp này thống trị giai cấp khác", "c": "Nhà nước ra đời là sản phẩm của xã hội có giai cấp", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 164, "q": "Chủ quyền quốc gia là:", "a": "Quyền độc lập tự quyết của quốc gia trong lĩnh vực đối nội", "b": "Quyền độc lập tự quyết của quốc gia trong lĩnh vực đối ngoại", "c": "Quyền ban hành văn bản pháp luật", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 165, "q": "Công dân khi tham gia các quan hệ xã hội đều thực hiện cách xử sự phù hợp với quy định của pháp luật là biểu hiện của…", "a": "Ban hành pháp luật", "b": "Xây dựng pháp luật", "c": "Thực hiện pháp luật", "d": "Phổ biến pháp luật", "ans": "c"}, {"num": 166, "q": "Lịch sử xã hội loài người đã tồn tại ...... kiểu nhà nước, bao gồm các kiểu nhà nước là .............", "a": "4 – chủ nô – phong kiến – tư hữu – XHCN", "b": "4 – chủ nô – phong kiến – tư sản – XHCN", "c": "4 – chủ nô – chiếm hữu nô lệ – tư bản - XHCN", "d": "4 – địa chủ – nông nô, phong kiến – tư bản – XHCN", "ans": "b"}, {"num": 167, "q": "Trong các hành vi dưới đây hành vi nào thể hiện công dân áp dụng pháp luật?", "a": "Người tham gia giao thông không vượt qua ngã tư khi có tín hiệu đèn đỏ", "b": "Công dân A gửi đơn khiếu nại lên cơ quan nhà nước", "c": "Cảnh sát giao thông xử phạt người không đội mũ bảo hiểm", "d": "Anh A và chị B đến UBND phường đăng ký kết hôn", "ans": "c"}, {"num": 168, "q": "Chọn phương án đúng nhất: Thế nào là người có năng lực trách nhiệm pháp lý?", "a": "Là người đạt một độ tuổi nhất định theo qui định của pháp luật, có thể nhận thức và điều khiển hành vi của mình", "b": "Là người không mắc bệnh tâm thần hoặc một bệnh khác làm mất khả năng nhận thức", "c": "Là người tự quyết định cách xử sự của mình và độc lập chịu trách nhiệm về hành vi đã thực hiện", "d": "Là người đạt một độ tuổi nhất định theo qui định của pháp luật", "ans": "a"}, {"num": 169, "q": "Tuân thủ pháp luật là hình thức thực hiện pháp luật, trong đó các cá nhân, tổ chức không làm những điều mà pháp luật…", "a": "cho phép làm", "b": "quy định phải làm", "c": "không bắt buộc", "d": "quy định cấm", "ans": "d"}, {"num": 170, "q": "Tính giai cấp của pháp luật thể hiện ở chỗ….", "a": "Pháp luật là sản phẩm của xã hội có giai cấp", "b": "Pháp luật là ý chí của giai cấp thống trị", "c": "Pháp luật là công cụ để điều chỉnh các mối quan hệ giai cấp", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 171, "q": "Nhà nước là:", "a": "Một tổ chức trong xã hội có giai cấp", "b": "Một tổ chức xã hội có chủ quyền quốc gia", "c": "Một tổ chức xã hội có luật lệ", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 172, "q": "Chọn phương án đúng nhất: Hình thức nhà nước là cách tổ chức bộ máy quyền lực nhà nước và phương pháp thực hiện quyền lực nhà nước. Hình thức nhà nước được thể hiện chủ yếu ở ............ khía cạnh; đó là ...................", "a": "3 – hình thức chính thể, hình thức cấu trúc nhà nước và chế độ KT – XH", "b": "3 – hình thức chính thể, hình thức cấu trúc và chế độ chính trị", "c": "3 – hình thức chuyên chính, hình thức cấu trúc nhà nước và chế độ KT – XH", "d": "3 – hình thức chuyên chính, hình thức cấu trúc nhà nước và chế độ chính trị", "ans": "b"}, {"num": 173, "q": "Người thuê nhà tự sửa chữa, cải tạo nhà mà không hỏi ý kiến của chủ nhà là hành vi…:", "a": "vi phạm hình sự", "b": "vi phạm hành chính", "c": "vi phạm dân sự", "d": "vi phạm kỉ luật", "ans": "c"}, {"num": 174, "q": "Khả năng nhà nước thừa nhận cho chủ thể bằng hành vi của mình có thể xác lập và thực hiện quyền hoặc nghĩa vụ pháp lý, gọi là?", "a": "Khả năng hành vi", "b": "Năng lực pháp luật", "c": "Năng lực hành vi", "d": "Năng lực pháp lý", "ans": "c"}, {"num": 175, "q": "Năng lực pháp luật và năng lực hành vi là những thuộc tính không tách rời của mỗi cá nhân, đều do nhà nước thừa nhận cho họ nên gọi là?", "a": "Thuộc tính tự nhiên", "b": "Năng lực pháp lý", "c": "Thuộc tính pháp lý", "d": "Tất cả đều đúng", "ans": "c"}, {"num": 176, "q": "Khẳng định nào sau đây là SAI?", "a": "Năng lực pháp luật là tiền đề của năng lực hành vi", "b": "Năng lực hành vi đầy đủ chỉ có ở những chủ thể đáp ứng đầy đủ các điều kiện do pháp luật quy định", "c": "Năng lực pháp luật và năng lực hành vi là những thuộc tính tự nhiên của mỗi cá nhân, có sẵn khi cá nhân sinh ra", "d": "Năng lực chủ thể pháp luật luôn mang tính giai cấp", "ans": "c"}, {"num": 177, "q": "Chọn phương án đùng nhất: Cấu thành của vi phạm pháp luật bao gồm:", "a": "Giả định, quy định, chế tài", "b": "Chủ thể, khách thể", "c": "Mặt chủ quan, mặt khách quan", "d": "Chủ thể, khách thể, mặt chủ quan, mặt khách quan", "ans": "d"}, {"num": 178, "q": "Anh A sử dụng điện thoải di động khi đang điều khiển xe máy, công an xử phạt hành chính anh A. Việc làm của công an là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Ban hành pháp luật", "b": "Tuân thủ pháp luật", "c": "Thi hành pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 179, "q": "“Pháp luật là hệ thống quy tắc xử sự mang tính ....................., do .................. ban hành và bảo đảm thực hiện, thể hiện ....................... của giai cấp thống trị và phụ thuộc vào các điều kiện .................. là nhân tố điều chỉnh các quan hệ xã hội”.", "a": "Bắt buộc – quốc hội – ý chí – chính trị", "b": "Bắt buộc chung – nhà nước – lý tưởng – chính trị", "c": "Bắt buộc – quốc hội – lý tưởng – kinh tế xã hội", "d": "Bắt buộc chung – nhà nước – ý chí – kinh tế xã hội", "ans": "d"}, {"num": 180, "q": "Chọn phương án đúng nhất: Hình thức pháp luật là cách thức mà giai cấp thống trị sử dụng để nâng ý chí của giai cấp mình lên thành pháp luật. Trong lịch sử loài người đã có ............ hình thức pháp luật, đó là ..................", "a": "4 – tập quán pháp, tiền lệ pháp, điều lệ pháp và Văn bản quy phạm pháp luật", "b": "3 – tập quán pháp, tiền lệ pháp, văn bản quy phạm pháp luật", "c": "2 – tập quán pháp và văn bản quy phạm pháp luật", "d": "1 – văn bản quy phạm pháp luật", "ans": "b"}, {"num": 181, "q": "Chọn phương án đúng nhất: Quy phạm pháp luật là quy tắc xử sự mang tính .................... do ................... ban hành và bảo đảm thực hiện, thể hiện ý chí và bảo vệ lợi ích của giai cấp thống trị để điều chỉnh các ...........................", "a": "Bắt buộc chung – nhà nước – quan hệ pháp luật", "b": "Bắt buộc – nhà nước – quan hệ xã hội", "c": "Bắt buộc chung – quốc hội – quan hệ xã hội", "d": "Bắt buộc chung – nhà nước – quan hệ xã hội", "ans": "d"}, {"num": 182, "q": "Chọn phương án đúng nhất: Chế tài có các loại nào sau đây?", "a": "Chế tài hình sự và chế tài hành chính", "b": "Chế tài hình sự, chế tài hành chính và chế tài dân sự", "c": "Chế tài hình sự, chế tài hành chính, chế tài kỷ luật và chế tài dân sự", "d": "Chế tài hình sự, chế tài hành chính, chế tài kỷ luật, chế tài dân sự và chế tài bắt buộc", "ans": "c"}, {"num": 183, "q": "Tập quán pháp là:", "a": "Biến đổi những tục lệ, tập quán có sẵn thành pháp luật", "b": "Biến đổi những thói quen hành xử của con người trong lịch sử thành pháp luật", "c": "Biến đổi những quy phạm tôn giáo thành quy phạm pháp luật", "d": "Tất cả đều sai", "ans": "a"}, {"num": 184, "q": "Pháp luật được hiểu là?", "a": "quy định chung", "b": "quy tắc xử sự chung", "c": "quy tắc xử sự riêng", "d": "quy định riêng", "ans": "b"}, {"num": 185, "q": "Người chưa thành niên, theo qui định pháp luật Việt Nam là người chưa đủ…", "a": "18 tuổi", "b": "16 tuổi", "c": "15 tuổi", "d": "17 tuổi", "ans": "a"}, {"num": 186, "q": "Cơ quan thường trực của Quốc hội là:", "a": "Hội đồng dân tộc", "b": "(cid:0)y ban Quốc hội", "c": "(cid:0)y ban thường vụ Quốc hội", "d": "(cid:0)y ban nhân dân", "ans": "c"}, {"num": 187, "q": "Ông A vận chuyển gia cầm bị bệnh, bị cơ quan có thẩm quyền phát hiện và buộc phải tiêu hủy hết số gia cầm bị bệnh này. Đây là biện pháp chế tài:", "a": "Dân sự", "b": "Hình sự", "c": "Kỷ luật", "d": "Hành chính", "ans": "d"}, {"num": 188, "q": "“Người nào quảng cáo gian dối về hàng hóa, dịch vụ gây hậu quả nghiêm trọng đã bị xử phạt hành chính về hành vi này hoặc đã bị kết án về tội này, chưa được xóa án tích mà còn vi phạm thì bị phạt tiền từ 10 triệu đến 100 triệu đồng, cải tạo không giam giữ đến 3 năm hoặc bị phạt tù từ 6 tháng đến 3 năm”. Bộ phận giả định là…", "a": "Người nào quảng cáo gian dối về hàng hóa về dịch vụ", "b": "Người nào quảng cáo gian dối về hàng hóa dịch vụ gây hậu quả nghiêm trọng", "c": "Người nào quảng cáo gian dối về hàng hóa dịch vụ gây hậu quả nghiêm trọng đã bị xử phạt hành chính về hành vi này", "d": "Người nào quảng cáo gian dối về hàng hóa, dịch vụ gây hậu quả nghiêm trọng đã bị xử phạt hành chính về hành vi này hoặc đã bị kết án về tội này, chưa được xóa án tích mà còn vi phạm", "ans": "d"}, {"num": 189, "q": "Nhận định nào sau đây SAI khi đề cập đến chức năng của pháp luật?", "a": "Pháp luật bảo vệ tất cả các quan hệ xã hội", "b": "Pháp luật tác động đến các quan hệ xã hội chủ yếu, tạo hành lang pháp lý an toàn cho quan hệ xã hội đó tồn tại, phát triển", "c": "Chức năng giáo dục của pháp luật thể hiện tính răn đe đối với hành vi vi phạm pháp luật và phòng ngừa chung cho toàn xã hội", "d": "Không đáp án nào sai", "ans": "a"}, {"num": 190, "q": "Người lao động đình công theo quy định pháp luật đòi tăng lương, giảm giờ làm, thể hiện vai trò nào sau đây của pháp luật?", "a": "Pháp luật làm ổn định những quan hệ mới", "b": "Pháp luật là phương tiện để Nhà nước quản lý mọi mặt đời sống xã hội", "c": "Pháp luật là phương tiện để bảo vệ các quyền, lợi ích hợp pháp của công dân", "d": "Pháp luật là cơ sở để tạo lập mối quan hệ đối ngoại", "ans": "c"}, {"num": 191, "q": "Năng lực của chủ thể bao gồm:", "a": "Năng lực pháp luật và năng lực hành vi", "b": "Năng lực pháp luật và năng lực công dân", "c": "Năng lực hành vi và năng lực nhận thức", "d": "Năng lực hành vi và năng lực nhận thức", "ans": "a"}, {"num": 192, "q": "Cá nhân, tổ chức thi hành pháp luật tức là thực hiện đầy đủ những nghĩa vụ, chủ động làm những gì mà pháp luật…", "a": "quy định làm", "b": "quy định phải làm", "c": "cho phép làm", "d": "không cấm", "ans": "b"}, {"num": 193, "q": "Anh B săn bắt động vật quý hiếm trong rừng. Trong trường hợp này anh B đã…", "a": "không thi hành pháp luật", "b": "không sử dụng pháp luật", "c": "không áp dụng pháp luật", "d": "không tuân thủ pháp luật", "ans": "d"}, {"num": 194, "q": "Qua kiểm tra cơ quan của anh C phát hiện anh C thường xuyên đi làm muộn và nhiều lần tự ý nghỉ việc không có lí do. Trong trường hợp này, anh C đã…", "a": "vi phạm dân sự", "b": "vi phạm hành chính", "c": "vi phạm kỉ luật", "d": "vi phạm hình sự", "ans": "c"}, {"num": 195, "q": "Những quy tắc xử sự chung, được áp dụng nhiều lần, ở nhiều nơi, đối với tất cả mọi người, trong mọi lĩnh vực của đời sống xã hội là nội dung đặc trưng nào dưới đây của pháp luật?", "a": "Tính bắt buộc chung", "b": "Tính quyền lực", "c": "Tính chặt chẽ về hình thức", "d": "Tính quy phạm phổ biến", "ans": "d"}, {"num": 196, "q": "Sự xuất hiện của nhà nước cổ đại nào sau đây có nguyên nhân là do mâu thuẫn giai cấp gay gắt đến mức không thể điều hòa được:", "a": "Nhà nước Đại Việt", "b": "Nhà nước Rôma", "c": "Nhà nước Chămpa", "d": "Các nhà nước phương Đông", "ans": "b"}, {"num": 197, "q": "Theo học thuyết Mác – Lênin, nhận định nào sau đây là đúng: thay đổi qua các kiểu nhà nước khác nhau nhà nước khác nhau kiểu nhà nước khác nhau nước là không đổi qua các kiểu nhà nước khác nhau", "a": "Tính chất giai cấp của nhà nước không đổi nhưng bản chất của nhà nước thì", "b": "Tính chất giai cấp và bản chất của nhà nước không thay đổi qua các kiểu", "c": "Tính chất giai cấp và bản chất của nhà nước luôn luôn thay đổi qua các", "d": "Tính chất giai cấp của nhà nước luôn luôn thay đổi, còn bản chất của nhà", "ans": "b"}, {"num": 198, "q": "Một công ty xã chất thải ra sông làm cá chết hàng loạt, gây ô nhiễm nặng môi trường. Trách nhiệm pháp lý áp dụng đối với công ty này là:", "a": "Trách nhiệm hành chính", "b": "Trách nhiệm hình sự", "c": "Trách nhiệm hành chính và trách nhiệm dân sự", "d": "Trách nhiệm hình sự và trách nhiệm dân sự", "ans": "c"}, {"num": 199, "q": "Chọn nhận định SAI:", "a": "Phó thủ tướng không nhất thiết phải là đại biểu Quốc hội", "b": "Năng lực pháp luật xuất hiện từ khi con người được sinh ra", "c": "Năng lực lao động xuất hiện từ khi công dân đủ 16 tuổi", "d": "Năng lực pháp luật là tiền đề của năng lực hành vi", "ans": "c"}, {"num": 200, "q": "Để truy cứu trách nhiệm pháp lý cần xác định?", "a": "Lỗi của chủ thể vi phạm pháp luật", "b": "Hành vi trái pháp luật của chủ thể", "c": "Hậu quả gây thiệt hại cho xã hội", "d": "Có hành vi vi phạm pháp luật xảy ra, còn thời hiệu truy cứu trách nhiệm pháp lý", "ans": "d"}, {"num": 201, "q": "Quy định thường gặp trong pháp luật hành chính:", "a": "Quy định dứt khoát", "b": "Quy định không dứt khoát", "c": "Quy định giao quyền", "d": "Tất cả đều sai", "ans": "a"}, {"num": 202, "q": "Hình thức thể hiện của pháp luật là các văn bản có chứa…", "a": "quy chế chung", "b": "quy định bắt buộc", "c": "chuẩn mực chung", "d": "quy phạm pháp luật", "ans": "c"}, {"num": 203, "q": "Vi phạm hình sự là…", "a": "Hành vi rất nguy hiểm cho xã hội", "b": "Hành vi nguy hiểm cho xã hội", "c": "Hành vi tương đối nguy hiểm cho xã hội", "d": "Hành vi đặc biệt nguy hiểm cho xã hội", "ans": "b"}, {"num": 204, "q": "Nội dung của văn bản quy phạm pháp luật đòi hỏi phải được diễn đạt…", "a": "chính xác, một nghĩa", "b": "chính xác, đa nghĩa", "c": "tương đối chính xác, một nghĩa", "d": "tương đối chính xác, đa nghĩa", "ans": "a"}, {"num": 205, "q": "Người nào tuy có điều kiện mà không cứu giúp người đang ở trong tình trạng nguy hiểm đến tính mạng, dẫn đến hậu quả người đó chết, thì…", "a": "vi phạm pháp luật dân sự", "b": "phải chịu trách nhiệm hình sự", "c": "vi phạm pháp luật hành chính", "d": "bị xử phạt hành chính", "ans": "b"}, {"num": 206, "q": "Ông B lừa chị C bằng cách mượn của chị 10 triệu đồng nhưng đến ngày hẹn ông B đã không chịu trả cho chị C số tiền trên. Chị C đã làm đơn kiện ông B ra tòa. Việc chị C kiện ông B là hành vi…", "a": "áp dụng pháp luật", "b": "tuân thủ pháp luật", "c": "thi hành pháp luật", "d": "sử dụng pháp luật", "ans": "d"}, {"num": 207, "q": "Chọn phương án đúng nhất: Các hình thức thực hiện pháp luật bao gồm:", "a": "Tuân thủ pháp luật và thực thi pháp luật", "b": "Tuân thủ pháp luật và sử dụng pháp luật", "c": "Áp dụng pháp luật và thực thi pháp luật", "d": "Sử dụng pháp luật, tuân thủ pháp luật, thực thi pháp luật và áp dụng pháp luật", "ans": "d"}, {"num": 208, "q": "Hành vi nào sau đây là vi phạm pháp luật dân sự?", "a": "Thành phố Huế", "b": "Thành phố Cần Thơ", "c": "Thành phố Đà Nẵng", "d": "Thành phố Hải Phòng", "ans": "d"}, {"num": 209, "q": "Thành phố nào sau đây của Việt Nam không phải là thành phố trực thuộc trung ương", "a": "Thành phố Huế", "b": "Thành phố Cần Thơ", "c": "Thành phố Đà Nẵng", "d": "Thành phố Hải Phòng", "ans": "a"}, {"num": 210, "q": "Phương hướng chính để đề phòng và hạn chế những hành vi vi phạm pháp luật là…", "a": "xử lý nghiêm minh các hành vi vi phạm pháp luật", "b": "hoàn chỉnh cơ chế thực thi pháp luật một cách có hiệu quả", "c": "xây dựng và hoàn chỉnh hệ thống pháp luật", "d": "đẩy mạnh phát triển kinh tế song song với chính sách xã hội, xóa đói giảm nghèo, nâng cao dân trí", "ans": "c"}, {"num": 211, "q": "So với pháp luật thì đạo đức có phạm vi điều chỉnh…", "a": "rộng hơn", "b": "hẹp hơn", "c": "như nhau", "d": "bằng nhau", "ans": "a"}, {"num": 212, "q": "Chọn phương án đúng nhất: Mặt chủ quan của vi phạm pháp luật gồm?", "a": "Lỗi cố ý và lỗi vô ý", "b": "Cố ý trực tiếp và cố ý gián tiếp; vô ý vì quá tự tin và vô ý vì quá cẩu thả", "c": "Hành vi trái pháp luật và hậu quả nguy hiểm cho xã hội", "d": "Lỗi; động cơ; mục đích", "ans": "d"}, {"num": 213, "q": "Quyền công tố trước tòa là:", "a": "Quyền truy tố cá nhân, tổ chức ra trước pháp luật", "b": "Quyền khiếu nại, tố cáo của công dân", "c": "Quyền xác định tội phạm", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 214, "q": "Người phải chịu trách nhiệm hành chính do mọi vi phạm hành chính mà mình gây ra theo quy định của pháp luật có độ tuổi là…", "a": "Từ đủ 18 tuổi trở lên", "b": "Từ 18 tuổi trở lên", "c": "Từ đủ 16 tuổi trở lên", "d": "Từ đủ 14 tuổi trở lên", "ans": "c"}, {"num": 215, "q": "Vi phạm dân sự là hành vi vi phạm pháp luật, xâm phạm tới…", "a": "Các quy tắc quản lý nhà nước", "b": "Các quan hệ tài sản và quan hệ nhân thân", "c": "Các quan hệ lao động, công vụ nhà nước", "d": "Tất cả đều sai", "ans": "b"}, {"num": 216, "q": "Người phải chịu trách nhiệm hình sự về mọi tội phạm do mình gây ra có độ tuổi theo quy định của pháp luật là người…", "a": "từ đủ 14 tuổi trở lên", "b": "từ đủ 16 tuổi trở lên", "c": "từ 18 tuổi trở lên", "d": "từ đủ 18 tuổi trở lên", "ans": "b"}, {"num": 217, "q": "Cơ sở để truy cứu trách nhiệm pháp lý là…", "a": "hành vi vi phạm pháp luật", "b": "tính chất phạm tội", "c": "mức độ gây thiệt hại của hành vi", "d": "khả năng nhận thức của chủ thể", "ans": "a"}, {"num": 218, "q": "Pháp luật là một trong những phương tiện để nhà nước thực hiện vai trò nào dưới đây?", "a": "bảo vệ các giai cấp", "b": "quản lý xã hội", "c": "bảo vệ công dân", "d": "quản lý văn hóa", "ans": "b"}, {"num": 219, "q": "Đâu là nguyên nhân chính dẫn đến vi phạm pháp luật?", "a": "Có sự yếu kém trong công tác quản lý xã hội, đôi chỗ còn buông lỏng kỉ cương; giám sát còn mang tính hình thức", "b": "Mặt trái của nền kinh tế thị trường tác động vào một bộ phận người dân, đặc biệt là giới trẻ", "c": "Thông qua các chiêu bài diễn biến hòa bình, các thế lực thù địch vẫn trực tiếp hoặc gián tiếp tìm cách chống phá Nhà nước ta", "d": "Do ảnh hưởng ít nhiều của tàn dư chế độ cũ để lại và ảnh hưởng của lối sống không lành mạnh", "ans": "a"}, {"num": 220, "q": "Đảng lãnh đạo nhà nước thông qua:", "a": "62", "b": "63", "c": "64", "d": "65", "ans": "d"}, {"num": 221, "q": "Số lượng tỉnh, thành phố trực thuộc trung ương hiện nay của nước CHXHCN Việt Nam là:", "a": "62", "b": "63", "c": "64", "d": "65", "ans": "b"}, {"num": 222, "q": "Quyền lực và hệ thống tổ chức quyền lực trong xã hội cộng sản nguyên thủy…", "a": "Hòa nhập vào xã hội và phục vụ lợi ích cho các thành viên trong xã hội", "b": "Đứng trên xã hội, tách khỏi xã hội và phục vụ lợi ích cho Hội đồng thị tộc, tù trưởng, các thủ lĩnh tôn giáo", "c": "Đứng trên xã hội, tách khỏi xã hội và phục vụ lợi ích cho các thành viên trong xã hội", "d": "Hòa nhập vào xã hội và phục vụ cho lợi ích của Hội đồng thị tộc, tù trưởng, các thủ lĩnh tôn giáo", "ans": "a"}, {"num": 223, "q": "Công dân bình đẳng về trách nhiệm pháp lý là…", "a": "Công dân ở bất kỳ độ tuổi nào vi phạm pháp luật đều bị xử lý như nhau", "b": "Công dân nào vi phạm quy định của cơ quan, đơn vị, đều phải chịu trách nhiệm kỷ luật", "c": "Công dân nào vi phạm pháp luật cũng bị xử lý theo quy định của pháp luật", "d": "Công dân nào do thiếu hiểu biết về pháp luật mà vi phạm pháp luật thì không phải chịu trách nhiệm pháp lý", "ans": "c"}, {"num": 224, "q": "Người bị bệnh tâm thần có hành vi trái pháp luật có được xem là vi phạm pháp luật không?", "a": "Có", "b": "Không", "c": "Tùy từng trường hợp", "d": "Tất cả đều sai", "ans": "b"}, {"num": 225, "q": "Trường hợp nào sau đây thì mới được bắt, giam, giữ người…", "a": "Bắt người khi đang bị tình nghi có hành vi vi phạm pháp luật", "b": "Bắt, giam, giữ người khi người này có dấu hiệu nghiện ma tuý", "c": "Bắt người phạm tội quả tang hoặc đang bị truy nã", "d": "Bắt giam người khi người này có người thân phạm pháp luật", "ans": "c"}, {"num": 226, "q": "Trách nhiệm pháp lý là trách nhiệm của:", "a": "Mọi người", "b": "Chủ thể vi phạm pháp luật", "c": "Chỉ những người có đủ 18 tuổi trở lên", "d": "Người có hành vi không hợp đạo đức", "ans": "b"}, {"num": 227, "q": "Hộ sản xuất – kinh doanh chủ động đăng kí khai thuế và nộp thuế là", "a": "tuân thủ pháp luật", "b": "thi hành pháp luật", "c": "sử dụng pháp luật", "d": "áp dụng pháp luật", "ans": "b"}, {"num": 228, "q": "Chọn phương án đúng nhất: Đối tượng của vi phạm hành chính là…", "a": "cá nhân", "b": "tổ chức", "c": "cá nhân và tổ chức", "d": "Cơ quan hành chính", "ans": "c"}, {"num": 229, "q": "Hành vi vi phạm các quy tắc, quy chế được xác lập trong một tổ chức, cơ quan, đơn vị là…", "a": "vi phạm hành chính", "b": "vi phạm dân sự", "c": "vi phạm kỷ luật", "d": "vi phạm hình sự", "ans": "c"}, {"num": 230, "q": "Luật Hiến pháp là một ngành luật chủ đạo trong hệ thống pháp luật Việt Nam vì….", "a": "Do Quốc hội - cơ quan quyền lực Nhà nước cao nhất ban hành", "b": "Quy định về những vấn đề cơ bản nhất, quan trọng nhất của Nhà nước", "c": "Có giá trị pháp lý cao nhất", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 231, "q": "Độ tuổi được ứng cử vào Quốc hội và Hội đồng nhân dân các cấp theo quy định của pháp luật ở nước ta là?", "a": "Đủ 18 tuổi trở lên", "b": "Đủ 19 tuổi trở lên", "c": "Đủ 20 tuổi trở lên", "d": "Đủ 21 tuổi trở lên", "ans": "d"}, {"num": 232, "q": "Hiến pháp có những đặc trưng khác với các văn bản pháp luật khác ở chỗ nào?", "a": "Hiến pháp chỉ quy định những vấn đề cơ bản nhất, quan trọng nhất của một Nhà nước, một xã hội làm cơ sở nền tảng cho hệ thống pháp luật", "b": "Hiến pháp có một phạm vi điều chỉnh rất rộng, trên tất cả các lĩnh vực, các văn bản pháp luật khác có phạm vi điều chỉnh hẹp hơn", "c": "Hiến pháp có hiệu lực pháp lý cao nhất và có thủ tục làm mới và sửa đổi đặc biệt là thủ tục lập Hiến", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 233, "q": "Pháp luật Việt Nam quy định người nào có quyền bầu cử ra cơ quan Quốc hội và Hội đồng nhân dân các cấp?", "a": "Tất cả công dân Việt Nam", "b": "Công dân Việt Nam 18 từ tuổi trở lên", "c": "Công dân Việt Nam 16 từ tuổi trở lên", "d": "Công dân Việt Nam 21 từ tuổi trở lên", "ans": "b"}, {"num": 234, "q": "Văn bản pháp luật nào quy định về quyền và nghĩa vụ cơ bản của công dân?", "a": "Luật Hành chính", "b": "Luật Dân sự", "c": "Luật Lao động", "d": "Luật Hiến pháp", "ans": "d"}, {"num": 235, "q": "Những quyền và nghĩa vụ của công dân được quy định trong?", "a": "Rất nhiều văn bản pháp luật khác nhau", "b": "Luật Dân sự", "c": "Luật Lao động", "d": "Hiến pháp", "ans": "a"}, {"num": 236, "q": "Hiến pháp Nhà nước Việt Nam quy định: Công dân đủ 21 tuổi trở lên có quyền ứng cử vào cơ quan nào sau đây?", "a": "Chính phủ", "b": "Quốc hội và Hội đồng nhân dân các cấp", "c": "(cid:0)y ban nhân dân các cấp", "d": "(cid:0)y ban nhân dân cấp tỉnh và tương đương", "ans": "b"}, {"num": 237, "q": "Hiến pháp 1992 đã được thay thế bằng Hiến pháp năm nào?", "a": "Năm 1996", "b": "Năm 1998", "c": "Năm 2013", "d": "Năm 2021", "ans": "c"}, {"num": 238, "q": "Hiến pháp được thông qua khi ít nhất có…", "a": "Một phần hai tổng số đại biểu Quốc hội biểu quyết tán thành", "b": "Hai phần ba tổng số đại biểu Quốc hội biểu quyết tán thành", "c": "Ba phần tư tổng số đại biểu Quốc hội biểu quyết tán thành", "d": "Một trăm phần trăm tổng số đại biểu Quốc hội biểu quyết tán thành", "ans": "b"}, {"num": 239, "q": "Những chức danh nào sau đây bắt buộc phải là đại biểu Quốc hội?", "a": "Phó Thủ tướng Chính phủ", "b": "Thủ tướng Chính phủ", "c": "Bộ trưởng", "d": "Chủ tịch UBND tỉnh, thành phố trực thuộc Trung ương", "ans": "b"}, {"num": 240, "q": "Chọn phương án đúng nhất: Cơ cấu bộ máy Nhà nước Cộng hòa XHCN Việt Nam bao gồm?", "a": "Quốc hội, Chính phủ, (cid:0)y ban nhân dân các cấp", "b": "Quốc hội, Viện Kiểm sát nhân dân, Tòa án nhân dân các cấp", "c": "Hệ thống cơ quan quyền lực, hệ thống cơ quan quản lý Nhà nước, hệ thống cơ quan kiểm sát, hệ thống cơ quan xét xử", "d": "Đảng Cộng sản Việt Nam, Quốc hội, chính phủ", "ans": "c"}, {"num": 241, "q": "Hệ thống cơ quan quyền lực Nhà nước bao gồm?", "a": "Quốc hội, Chính phủ", "b": "Quốc hội, (cid:0)y ban nhân dân các cấp", "c": "Chính phủ, (cid:0)y ban nhân dân các cấp", "d": "Quốc hội, Hội đồng nhân dân các cấp", "ans": "d"}, {"num": 242, "q": "Phương tiện nào dưới đây của nhà nước được xem là hiệu quả để quản lý xã hội?", "a": "Giáo dục", "b": "Phong tục", "c": "Nội quy", "d": "Pháp luật", "ans": "d"}, {"num": 243, "q": "Chính phủ nước Cộng hòa XHCN Việt Nam…", "a": "Là cơ quan trung tâm của Nhà nước, có thẩm quyền trong cả 3 lĩnh vực lập pháp, hành pháp, tư pháp", "b": "Là cơ quan Hành chính Nhà nước cao nhất, thực hiện quyền hành pháp, tư pháp", "c": "Là cơ quan Hành chính Nhà nước cao nhất, thực hiện quyền lập pháp, hành pháp, tư pháp", "d": "Là cơ quan chấp hành của Quốc hội, cơ quan Hành chính Nhà nước cao nhất, thực hiện quyền hành pháp", "ans": "d"}, {"num": 244, "q": "Chủ thể nào dưới đây sẽ đảm bảo cho pháp luật được thực hiện nghiêm minh?", "a": "Đảng cộng sản", "b": "Cơ quan", "c": "Cá nhân", "d": "Nhà nước", "ans": "d"}, {"num": 245, "q": "Để xử lý người có hành vi xâm hại đến lợi ích của giai cấp cầm quyền, Nhà nước sẽ sử dụng quyền lực có tính cưỡng chế, khẳng định này là nội dung nào dưới đây của pháp luật?", "a": "Đặc trưng của pháp luật", "b": "Bản chất của pháp luật", "c": "Vai trò của pháp luật", "d": "Chức năng của pháp luật", "ans": "b"}, {"num": 246, "q": "Phương pháp điều chỉnh của Luật Hành chính là?", "a": "Phương pháp bình đẳng, thỏa thuận", "b": "Phương pháp độc lập, tự định đoạt", "c": "Phương pháp mệnh lệnh đơn phương", "d": "Phương pháp quyền uy và phương pháp thông qua hoạt động của tổ chức công đoàn", "ans": "c"}, {"num": 247, "q": "Tìm đáp án Sai trong nhận định sau: Các cơ quan Hành chính nhà nước ở Trung ương bao gồm?", "a": "Chính phủ", "b": "(cid:0)y ban Thường vụ Quốc hội", "c": "Cơ quan ngang Bộ", "d": "Bộ", "ans": "b"}, {"num": 248, "q": "Chọn phương án đúng nhất: Cơ quan Hành chính Nhà nước cấp tỉnh bao gồm?", "a": "(cid:0)y ban nhân dân tỉnh, các Sở, phòng, ban thuộc (cid:0)y ban nhân dân tỉnh", "b": "(cid:0)y ban nhân dân tỉnh, Hội đồng nhân dân tỉnh", "c": "Hội đồng nhân dân, (cid:0)y ban nhân dân, các Sở, phòng, ban cấp tỉnh", "d": "(cid:0)y ban nhân dân, Hội đồng nhân dân, các tổ chức Đảng, đoàn thể cấp tỉnh", "ans": "a"}, {"num": 249, "q": "Thực hiện pháp luật là quá trình hoạt động có mục đích, làm cho các quy định của pháp luật đi vào cuộc sống, trở thành hành vi…", "a": "có ích của công dân", "b": "cơ bản của cá nhân", "c": "cốt lõi của cá nhân", "d": "hợp pháp của công dân", "ans": "d"}, {"num": 250, "q": "Độ tuổi bắt đầu chịu trách nhiệm hành chính là đủ?", "a": "14 tuổi", "b": "15 tuổi", "c": "16 tuổi", "d": "18 tuổi", "ans": "a"}, {"num": 251, "q": "A đã 15 tuổi thực hiện hành vi vi phạm hành chính với lỗi cố ý. Trách nhiệm hành chính đối với A như thế nào?", "a": "Có thể phạt cảnh cáo hoặc phạt tiền theo quy định của pháp luật", "b": "Chỉ có thể phạt cảnh cáo theo quy định của pháp luật", "c": "Cha mẹ hoặc người giám hộ của A phải chịu trách nhiệm thay vì A chưa thành niên", "d": "A dưới 16 tuổi nên chưa phải chịu trách nhiệm hành chính", "ans": "b"}, {"num": 252, "q": "Tìm đáp án đúng trong nhận định sau: C là người chưa thành niên thực hiện hành vi vi phạm hành chính?", "a": "C sẽ phải chịu trách nhiệm hành chính do lỗi cố ý nếu tuổi C từ đủ 14 đến dưới 16. Nếu C từ đủ 16 tuổi trở lên, có thể phải chịu trách nhiệm hành chính trong mọi trường hợp vi phạm", "b": "C không phải chịu trách nhiệm hành chính", "c": "C phải chịu trách nhiệm hành chính trong mọi trường hợp vi phạm", "d": "C chỉ phải chịu trách nhiệm hành chính khi C đủ 16 tuổi trở lên", "ans": "a"}, {"num": 253, "q": "Tìm đáp án đúng trong nhận định sau: T 17 tuổi thực hiện hành vi vi phạm hành chính và bị xử phạt tiền?", "a": "Mức tiền phạt đối với T giống như mức phạt đối với người thành niên", "b": "Mức tiền phạt đối với T không được quá 1/2 mức phạt đối với người thành niên. Trường hợp T không có tiền nộp phạt thì cha mẹ hoặc người giám hộ T phải nộp phạt thay", "c": "Trong mọi trường hợp, cha mẹ hoặc người giám hộ T phải nộp thay", "d": "Trường hợp T không có tiền nộp phạt thì áp dụng hình thức phạt cảnh cáo với T", "ans": "b"}, {"num": 254, "q": "Tính quy phạm phổ biến là đặc tính của:", "a": "Tập quán", "b": "Tôn giáo", "c": "Đạo đức", "d": "Pháp luật", "ans": "d"}, {"num": 255, "q": "Việc làm là…?", "a": "Mọi hoạt động lao động trong cơ quan Nhà nước", "b": "Mọi hoạt động lao động tạo ra thu nhập", "c": "Mọi hoạt động lao động tạo ra nguồn thu nhập không bị pháp luật cấm", "d": "Tất cả đều đúng", "ans": "c"}, {"num": 256, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ của nhà sản xuất, kinh doanh phải thực hiện…?", "a": "Giải quyết tình trạng thất nghiệp", "b": "Xóa đói giảm nghèo", "c": "Nộp thuế đầy đủ theo quy định của pháp luật", "d": "Đảm bảo đầy đủ đời sống của người lao động", "ans": "c"}, {"num": 257, "q": "Tiền lương là một chế định của ngành luật?", "a": "Dân sự", "b": "Hành chính", "c": "Bảo hiểm xã hội", "d": "Lao động", "ans": "d"}, {"num": 258, "q": "Hợp đồng lao động phải có nội dung chủ yếu nào sau đây?", "a": "Công việc phải làm, thời giờ làm việc, nghỉ ngơi", "b": "Tiền lương, địa điểm làm việc, thời hạn hợp đồng", "c": "Điều kiện về an toàn lao động, vệ sinh lao động và bảo hiểm xã hội đối với người lao động", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 259, "q": "Hợp đồng lao động loại nào có lợi nhất cho người lao động?", "a": "Hợp đồng có xác định thời hạn", "b": "Hợp đồng không xác định thời hạn", "c": "Hợp đồng theo mùa vụ", "d": "Các hợp đồng đều như nhau", "ans": "b"}, {"num": 260, "q": "Thời giờ làm việc theo quy định của Bộ luật Lao động là?", "a": "Không quá 10 giờ trong một ngày", "b": "Từ 8 đến 10 giờ trong một ngày", "c": "Tùy thỏa thuận giữa người lao động và người sử dụng lao động", "d": "Không quá 8 giờ trong một ngày hoặc 48 giờ trong một tuần", "ans": "d"}, {"num": 261, "q": "Thời giờ làm việc ban đêm theo quy định của Bộ luật Lao động được tính từ?", "a": "21 giờ đến 4 giờ sáng", "b": "22 giờ đến 5 giờ sáng", "c": "22 giờ đến 6 giờ sáng hoặc từ 21 giờ đến 5 giờ sáng tùy theo vùng khí hậu", "d": "tùy sự thỏa thuận giữa người lao động và người sử dụng lao động", "ans": "c"}, {"num": 262, "q": "Nguyên tắc giao kết hợp đồng lao động là?", "a": "Tự nguyện", "b": "Thỏa thuận", "c": "Bình đẳng", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 263, "q": "Luật Lao động quy định: Đối với hợp đồng lao động không xác định thời hạn, người lao động có quyền đơn phương chấm dứt hợp đồng khi?", "a": "Báo cho người sử dụng lao động biết trước ít nhất 45 ngày", "b": "Do ốm đau, đã điều trị 6 tháng nhưng chưa khỏi", "c": "Do tai nạn, đã điều trị 6 tháng nhưng chưa khỏi", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 264, "q": "Thủ tục kết hôn theo quy định của Luật Hôn nhân - gia đình Việt Nam là…?", "a": "Chỉ cần tổ chức tiệc cưới", "b": "Phải đăng ký kết hôn ở (cid:0)y ban nhân dân nơi bên nam thường trú", "c": "Phải đăng ký kết hôn tại Tòa án", "d": "Phải đăng ký tại (cid:0)y ban nhân dân nơi bên nam hoặc bên nữ thường trú", "ans": "d"}, {"num": 265, "q": "Luật Lao động quy định: Tranh chấp lao động là tranh chấp về quyền và lợi ích phát sinh trong quan hệ lao động giữa?", "a": "Người lao động với tập thể lao động", "b": "Tổ chức Công đoàn với người sử dụng lao động", "c": "Người lao động, tập thể lao động với người sử dụng lao động", "d": "Người lao động, tập thể lao động với tổ chức Công đoàn", "ans": "c"}, {"num": 266, "q": "Khi nghiên cứu về quyền của người sử dụng lao động thì khẳng định nào sau đây là sai?", "a": "Được tuyển chọn người lao động, bố trí công việc theo quy định của pháp luật", "b": "Được khen thưởng, xử lí người lao động vi phạm kỉ luật theo quy định của pháp luật", "c": "Được đơn phương chấm dứt hợp đồng lao động trong mọi trường hợp", "d": "Được cử đại diện để kí kết thỏa ước lao động tập thể", "ans": "c"}, {"num": 267, "q": "Người lao động có nghĩa vụ?", "a": "Chấp hành đúng quy định về an toàn lao động", "b": "Hoàn thành những công việc được giao trong mọi trường hợp", "c": "Tuân theo sự điều động của người sử dụng lao động trong mọi trường hợp", "d": "Tất cả đều đúng", "ans": "a"}, {"num": 268, "q": "Tìm đáp án sai trong nhận định sau: Người có quyền chiếm hữu hợp pháp đối với tài sản là?", "a": "Chủ sở hữu đối với tài sản đó", "b": "Chỉ có thể là chủ sở hữu đối với tài sản đó", "c": "Người được ủy quyền hợp pháp", "d": "Tất cả đều đúng", "ans": "b"}, {"num": 269, "q": "Người sử dụng lao động có nghĩa vụ?", "a": "Thực hiện đúng hợp đồng lao động", "b": "Bảo đảm an toàn lao động cho người lao động", "c": "Tôn trọng nhân phẩm của người lao động", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 270, "q": "Sự thỏa thuận nào làm phát sinh hợp đồng dân sự?", "a": "Mọi sự thỏa thuận", "b": "Mọi sự thỏa thuận đuợc lập thành văn bản", "c": "Mọi sự thỏa thuận nhằm làm phát sinh, thay đổi, chấm dứt quyền và nghĩa vụ dân sự", "d": "Tất cả đều đúng", "ans": "c"}, {"num": 271, "q": "Chọn đáp án đúng: Chủ thể của pháp luật dân sự là cá nhân, có thể là?", "a": "Công dân Việt Nam", "b": "Người nước ngoài", "c": "Người không quốc tịch", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 272, "q": "Quyền chiếm hữu, sử dụng và định đoạt tài sản chung phải do…", "a": "Vợ là người nắm giữ kinh tế nên quyết định", "b": "Vợ và chồng cùng nhau thỏa thuận", "c": "Chồng là người làm ra kinh tế nên quyết định", "d": "Vợ chồng nhờ cha mẹ quyết định hộ", "ans": "b"}, {"num": 273, "q": "Quyền sử dụng đối với tài sản là một loại quyền năng của?", "a": "Quyền chiếm hữu", "b": "Quyền định đoạt", "c": "Quyền sở hữu", "d": "Quyền khai thác lợi ích tài sản", "ans": "c"}, {"num": 274, "q": "Quyền sở hữu đối với tài sản bao gồm?", "a": "Quyền quyết định số phận của tài sản", "b": "Quyền nắm giữ, quản lý tài sản", "c": "Quyền khai thác lợi ích tài sản", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 275, "q": "Quyền sử dụng đối với tài sản là một loại quyền năng của?", "a": "Quyền chiếm hữu", "b": "Quyền định đoạt", "c": "Quyền sở hữu", "d": "Quyền khai thác lợi ích tài sản", "ans": "c"}, {"num": 276, "q": "Khẳng định nào dưới đây không đúng khi các doanh nghiệp thực hiện bình đẳng trong kinh doanh?", "a": "Có quyền chủ động mở rộng quy mô sản xuất", "b": "Có quyền chủ động tìm kiếm thị trường đầu tư", "c": "Có quyền tự chủ đăng kí kinh doanh", "d": "Có quyền tự ý chấm dứt hợp đồng", "ans": "d"}, {"num": 277, "q": "Tìm đáp án đúng trong tình huống sau: A mua của B một máy vi tính xách tay và không biết đó là đồ do B trộm cắp mà có?", "a": "A là người chiếm hữu hợp pháp", "b": "A là người chiếm hữu bất hợp pháp ngay tình", "c": "A là người chiếm hữu bất hợp pháp không ngay tình", "d": "Tất cả đều sai", "ans": "b"}, {"num": 278, "q": "Việc chiếm hữu của một người với đối với một tài sản nhưng không biết đó là chiếm hữu bất hợp pháp thì?", "a": "Đều là chiếm hữu hợp pháp", "b": "Có thể là chiếm hữu bất hợp pháp ngay tình hoặc chiếm hữu bất hợp pháp không ngay tình", "c": "Đều là chiếm hữu bất hợp pháp ngay tình", "d": "Đều là chiếm hữu bất hợp pháp không ngay tình", "ans": "c"}, {"num": 279, "q": "Quyền nào sau đây KHÔNG phải là quyền nhân thân quy định trong Luật Dân sự năm 2015?", "a": "Quyền được thông tin", "b": "Quyền xác định lại giới tính", "c": "Quyền được bảo vệ danh dự, nhân phẩm", "d": "Quyền được khai sinh", "ans": "a"}, {"num": 280, "q": "A ủy quyền cho B bán một ngôi nhà?", "a": "B có quyền định đoạt đối với ngôi nhà đó", "b": "B có quyền chiếm hữu đối với ngôi nhà đó", "c": "B có quyền sở hữu đối với ngôi nhà đó", "d": "Tất cả các đáp án đều sai", "ans": "d"}, {"num": 281, "q": "Tìm đáp án đúng trong các nhận định sau?", "a": "Mọi hợp đồng dân sự đều phải được lập thành văn bản", "b": "Mọi hợp đồng dân sự đều phải được lập thành văn bản có công chứng, chứng thực", "c": "Hợp đồng dân sự về mua bán nhà cửa, đất đai bắt buộc phải có công chứng, chứng thực", "d": "Tất cả đều đúng", "ans": "c"}, {"num": 282, "q": "Chọn đáp án đúng: Luật Dân sự điều chỉnh những quan hệ nào?", "a": "Quan hệ nhân thân và quan hệ kinh tế", "b": "Quan hệ nhân thân và quan hệ tài sản", "c": "Quan hệ tài sản và quan hệ gia đình", "d": "Tất cả các quan hệ xã hội có liên quan đến tài sản", "ans": "b"}, {"num": 283, "q": "Nội dung của quyền sở hữu bao gồm?", "a": "Quyền chiếm hữu", "b": "Quyền sử dụng", "c": "Quyền định đoạt", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 284, "q": "Khách thể của quyền sở hữu bao gồm?", "a": "Tài sản là vật có thực", "b": "Tiền và giấy tờ trị giá được bằng tiền", "c": "Các quyền về tài sản", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 285, "q": "Theo quy định của pháp luật, bình đẳng trong kinh doanh được thực hiện trong quan hệ nào dười đây?", "a": "Sản xuất", "b": "Cạnh tranh", "c": "Kinh tế", "d": "Chính trị", "ans": "c"}, {"num": 286, "q": "Việc giao kết hợp đồng lao động giữa người lao động và người sử dụng lao động nhằm mục tiêu nào dưới đây trong thực hiện quyền và nghĩa vụ của hai bên?", "a": "Tạo khung pháp lý", "b": "Tạo cơ sở pháp lý", "c": "Tạo hành lang pháp lý", "d": "Tạo điều kiện pháp lý", "ans": "b"}, {"num": 287, "q": "Theo quy định của Luật Hôn nhân - gia đình thì những trường hợp nào sau đây không bị cấm kết hôn?", "a": "Có quan hệ trong phạm vi ba đời, có cùng dòng máu về trực hệ", "b": "Kết hôn với người bị nhiễm HIV/AIDS", "c": "Người mất năng lực hành vi dân sự", "d": "Những người cùng giới tính", "ans": "b"}, {"num": 288, "q": "Thủ tục kết hôn theo quy định của Luật Hôn nhân - gia đình Việt Nam là?", "a": "Chỉ cần tổ chức tiệc cưới", "b": "Phải đăng ký kết hôn ở (cid:0)y ban nhân dân nơi bên nam thường trú", "c": "Phải đăng ký kết hôn tại Tòa án", "d": "Phải đăng ký tại (cid:0)y ban nhân dân nơi bên nam hoặc bên nữ thường trú", "ans": "d"}, {"num": 289, "q": "Khi tìm hiểu về quyền và nghĩa vụ tài sản của vợ chồng thì khẳng định nào sau đây là đúng?", "a": "Vợ, chồng có trách nhiệm ngang nhau đối với tài sản chung và tài sản riêng của vợ, chồng", "b": "Vợ chồng có quyền ủy quyền cho nhau trong mọi vấn đề", "c": "Vợ, chồng có quyền có tài sản riêng", "d": "Khi ly hôn thì toàn bộ tài sản của vợ, chồng phải chia đôi", "ans": "c"}, {"num": 290, "q": "Năng lực hành vi đầy đủ của công dân khi tham gia quan hệ tố tụng dân sự là?", "a": "Người không mắc bệnh tâm thần, chưa thành niên", "b": "Người không mắc bệnh tâm thần, đủ 16 tuổi trở lên", "c": "Người không mắc bệnh tâm thần, đủ 18 tuổi trở lên", "d": "Người không mắc bệnh tâm thần, đủ 21 tuổi trở lên", "ans": "c"}, {"num": 291, "q": "Tìm đáp án đúng trong các nhân định sau: A 17 tuổi được hưởng thừa kế một ngôi nhà của cha mẹ?", "a": "A không thể tự mình ký hợp đồng để bán ngôi nhà mà phải được người giám hộ thay mặt ký", "b": "A có thể tự mình ký hợp đồng để bán ngôi nhà", "c": "A chỉ được ký hợp đồng bán ngôi nhà nếu họ hàng của A đồng ý", "d": "A được bán ngôi nhà khi vì đã 17 tuổi", "ans": "a"}, {"num": 292, "q": "Trình tự, thủ tục giải quyết một vụ án dân sự nói chung là?", "a": "Thụ lý vụ án - hòa giải - xét xử - thi hành án dân sự", "b": "Xét xử sơ thẩm - xét xử phúc thẩm - xét lại bản án theo thủ tục giám đốc thẩm, tái thẩm", "c": "Hòa giải - xét xử sơ thẩm - xét xử phúc thẩm", "d": "Xét xử sơ thẩm - xét xử phúc thẩm", "ans": "a"}, {"num": 293, "q": "Thừa kế là?", "a": "Sự chuyển quyền sở hữu đối với tài sản của cha mẹ, ông bà cho con, cháu", "b": "Sự chuyển quyền sở hữu đối với tài sản của người chết cho người thừa kế thông qua ý nguyện cá nhân bằng di chúc hoặc căn cứ vào quy định của pháp luật", "c": "Sự chuyển quyền sở hữu đối với tài sản của người chết cho con cháu và được lập thành văn bản theo quy định của pháp luật", "d": "Tất cả đều không đúng", "ans": "b"}, {"num": 294, "q": "Theo quy định của pháp luật hình sự, hành vi nguy hiểm cho xã hội là hành vi:", "a": "Gây thiệt hại cho xã hội hoặc đe dọa gây thiệt hại đáng kể cho xã hội", "b": "Gây thiệt hại lợi ích của xã hội", "c": "Gây hoảng loạn về tinh thần cho mọi người", "d": "Trái với quy định của pháp luật", "ans": "a"}, {"num": 295, "q": "Tội phạm là:", "a": "Hành vi vi phạm pháp luật", "b": "Hành vi vi phạm pháp luật hình sự, dân sự hoặc hành chính", "c": "Người có hành vi gây hại cho xã hộ", "d": "Hành vi nguy hiểm cho xã hội, trái pháp luật hình sự và theo quy định của Bộ luật hình sự phải bị xử lý hình sự", "ans": "d"}, {"num": 296, "q": "Theo quy định của pháp luật Việt Nam, hình phạt được quy định trong:", "a": "Bộ luật Hình sự", "b": "Luật xử lý vi phạm hành chính", "c": "Luật giao thông đường bộ", "d": "Bộ luật Dân sự", "ans": "a"}, {"num": 297, "q": "Yếu tố nào sau đây là một trong những dấu hiệu cơ bản (đặc điểm) của tội phạm?", "a": "Trái với đạo đức xã hội", "b": "Vi phạm pháp luật", "c": "Phải đươc quy định trong Bộ luật Hình sự", "d": "Phải được quy định trong các văn bản quy phạm pháp luật", "ans": "c"}, {"num": 298, "q": "Luật Hình sự quy định về vấn đề nào sau đây?", "a": "Quy định về tội phạm", "b": "Quy định về hình phạt", "c": "Quy định về xử phạt vi phạm hành chính", "d": "Quy định về tội phạm, hình phạt và những vấn đề liên quan khác", "ans": "d"}, {"num": 299, "q": "Hình phạt nào sau đây chỉ được áp dụng đối với người phạm tội là người nước ngoài…", "a": "Phạt tiền", "b": "Cảnh cáo", "c": "Trục xuất", "d": "Cấm cư trú", "ans": "c"}, {"num": 300, "q": "Doanh nghiệp nhà nước bao gồm các doanh nghiệp do nhà nước nắm giữ ít nhất trên bao nhiêu phần trăm vốn điều lệ:", "a": "33%", "b": "50%", "c": "65%", "d": "75%", "ans": "b"}, {"num": 301, "q": "Chọn 1 nhận định đúng:", "a": "Sĩ quan, hạ sĩ quan chuyên nghiệp trong các đơn vị thuộc công an nhân dân Việt Nam có quyền thành lập và quản lý công ty tại Việt Nam", "b": "Công ty TNHH 2 thành viên trở lên được quyền phát hành cổ phần", "c": "Công ty TNHH 2 thành viên trở lên có từ 2 đến 70 thành viên", "d": "Doanh nghiệp tư nhân không phải là một pháp nhân", "ans": "d"}, {"num": 302, "q": "Căn cứ theo hình thức pháp lý, các loại hình doanh nghiệp ở Việt Nam hiện nay bao gồm:", "a": "Công ty cổ phần, công ty TNHH, công ty hợp danh, doanh nghiệp tư nhân, hộ kinh doanh.", "b": "Công ty cổ phần, công ty TNHH, công ty hợp danh", "c": "Công ty cổ phần, công ty TNHH, công ty hợp danh, doanh nghiệp tư nhân", "d": "Công ty cổ phần, công ty TNHH, doanh nghiệp tư nhân", "ans": "c"}, {"num": 303, "q": "Hành vi nào của người sử dụng đất không bị Luật Đất đai cấm?", "a": "Lấn, chiếm, hủy hoại đất", "b": "Sử dụng đất không đúng mục đích", "c": "Thực hiện giao dịch về quyền sử dụng đất mà không đăng ký với cơ quan nhà nước có thẩm quyền", "d": "Hưởng thành quả lao động, kết quả đầu tư trên đất", "ans": "d"}, {"num": 304, "q": "Theo Luật Đất đai 2013, trường hợp nào Nhà nước giao đất không thu tiền sử dụng đất?", "a": "Hộ gia đình, cá nhân được giao đất ở", "b": "Hộ gia đình, cá nhân trực tiếp sản xuất nông nghiệp, lâm nghiệp, nuôi trồng thủy sản, làm muối được giao đất nông nghiệp trong hạn mức quy định", "c": "Tổ chức kinh tế được giao đất để thực hiện dự án đầu tư xây dựng nhà ở để bán hoặc để bán kết hợp cho thuê", "d": "Tổ chức kinh tế được giao đất thực hiện dự án đầu tư hạ tầng nghĩa trang, nghĩa địa để chuyển nhượng quyền sử dụng đất gắn với hạ tầng", "ans": "b"}, {"num": 305, "q": "Người sử dụng đất không có quyền nào?", "a": "Được Nhà nước bảo hộ khi người khác xâm phạm quyền, lợi ích hợp pháp về đất đai của mình", "b": "Được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất", "c": "Được nhận chuyển quyền sử dụng đất nông nghiệp vượt hạn mức", "d": "Được bồi thường khi Nhà nước thu hồi đất theo quy định của Luật Đất đai", "ans": "c"}, {"num": 306, "q": "Hạn mức giao đất trồng cây hàng năm, đất nuôi trồng thủy sản, đất làm muối cho mỗi hộ gia đình, cá nhân trực tiếp sản xuất nông nghiệp là bao nhiêu?", "a": "Không quá 03 héc ta cho mỗi loại đất đối với tỉnh, thành phố trực thuộc trung ương thuộc khu vực Đông Nam Bộ và khu vực đồng bằng sông Cửu Long; Không quá 02 héc ta cho mỗi loại đất đối với tỉnh, thành phố trực thuộc trung ương khác", "b": "Không quá 02 héc ta cho mỗi loại đất đối với tỉnh, thành phố trực thuộc trung ương thuộc khu vực Đông Nam Bộ và khu vực đồng bằng sông Cửu Long; Không quá 03 héc ta cho mỗi loại đất đối với tỉnh, thành phố trực thuộc trung ương khác", "c": "Không quá 03 héc ta cho mỗi loại đất", "d": "Không quá 02 héc ta cho mỗi loại đất", "ans": "a"}, {"num": 307, "q": "Theo Luật Đất đai 2013, trường hợp nào Nhà nước cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất?", "a": "Người đang quản lý, sử dụng đất nông nghiệp thuộc quỹ đất công ích của xã, phường, thị trấn", "b": "Người mua nhà ở, tài sản khác gắn liền với đất", "c": "Người nhận khoán đất trong các nông trường, lâm trường, doanh nghiệp nông, lâm nghiệp, ban quản lý rừng phòng hộ, ban quản lý rừng đặc dụng", "d": "Người thuê, thuê lại đất của người sử dụng đất, trừ trường hợp thuê, thuê lại đất của nhà đầu tư xây dựng, kinh doanh kết cấu hạ tầng trong khu công nghiệp, cụm công nghiệp, khu chế xuất, khu công nghệ cao, khu kinh tế", "ans": "b"}, {"num": 308, "q": "Theo Luật Đất đai 2013, trường hợp nào Nhà nước giao đất có thu tiền sử dụng đất, cho thuê đất theo hình thức đấu giá quyền sử dụng đất?", "a": "Sử dụng đất để thực hiện dự án đầu tư xây dựng nhà ở tái định cư", "b": "Sử dụng đất được miễn tiền sử dụng đất, tiền thuê đất theo quy định", "c": "Cho thuê đất thuộc quỹ đất nông nghiệp sử dụng vào mục đích công ích để sản xuất nông nghiệp, lâm nghiệp, nuôi trồng thủy sản, làm muối", "d": "Sử dụng đất vào mục đích hoạt động khoáng sản", "ans": "c"}, {"num": 309, "q": "Kể từ ngày nhận được đơn yêu cầu giải quyết tranh chấp đất đai, trong thời hạn bao lâu Ủy ban nhân dân cấp xã phải tiến hành hòa giải tranh chấp đất đai?", "a": "Không quá 15 ngày", "b": "Không quá 20 ngày", "c": "Không quá 30 ngày", "d": "Không quá 45 ngày", "ans": "d"}, {"num": 310, "q": "Tranh chấp đất đai mà đương sự có Giấy chứng nhận quyền sử dụng đất và đã được hòa giải tại Ủy ban nhân dân cấp xã mà không thành thuộc thẩm quyền giải quyết của cơ quan nào?", "a": "(cid:0)y ban nhân dân", "b": "Tòa án nhân dân", "c": "Cơ quan Thanh tra", "d": "Phòng Tài nguyên và môi trường", "ans": "b"}, {"num": 311, "q": "Ông A đang sử dụng một thửa đất (từ năm 2006) nhưng không có giấy tờ gì về đất. Hiện ông có hộ khẩu thường trú tại địa phương (nơi có thửa đất) và trực tiếp sản xuất nông nghiệp tại vùng có điều kiện kinh tế - xã hội đặc biệt khó khăn, nay được Ủy ban nhân dân cấp xã nơi có đất xác nhận là người đã sử dụng đất ổn định, không có tranh chấp. Ông A muốn được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất thì ông A thuộc trường hợp nào dưới đây?", "a": "Không được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất", "b": "Được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất và phải nộp tiền sử dụng đất", "c": "Được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất và không phải nộp tiền sử dụng đất", "d": "Không được cấp Giấy chứng nhận quyền sử dụng đất, quyền sở hữu nhà ở và tài sản khác gắn liền với đất mà phải chuyển sang hình thức thuê đất", "ans": "c"}, {"num": 312, "q": "Thế nào là tham nhũng?", "a": "Tham nhũng là hành vi của cán bộ, công chức nhà nước đã lợi dụng chức vụ, quyền hạn đó vì vụ lợi.", "b": "Tham nhũnglà hành vi lợi dụng chức vụ, quyền hạn để vụ lợi.", "c": "Tham nhũng là hành vi của người có chức vụ, quyền hạn đã lợi dụng chức vụ, quyền hạn đó vì vụ lợi.", "d": "Tham nhũnglà hành vi cửa quyền, hách dịch, đòi hỏi, gây khó khăn, phiền hà của người có chức vụ, quyền hạn trong khi thực hiện nhiệm vụ, công vụ.", "ans": "c"}, {"num": 313, "q": "Công dân có quyền gì trong công tác phòng, chống tham nhũng?", "a": "Công dân chỉ có quyền phát hiện và báo tin về hành vi tham nhũng", "b": "Công dân chỉ có quyền giám sát việc thực hiện pháp luật về phòng, chống tham nhũng", "c": "Công dân chỉ có quyền phát hiện, kiến nghị với cơ quan nhà nước hoàn thiện pháp luật về phòng, chống tham nhũng và giám sát việc thực hiện pháp luật về phòng, chống tham nhũng", "d": "Công dân có quyền phát hiện, phản ánh, tố cáo, tố giác, báo tin về hành vi tham nhũng và được bảo vệ, khen thưởng theo quy định của pháp luật; có quyền kiến nghị với cơ quan nhà nước hoàn thiện pháp luật về phòng, chống tham nhũng và giám sát việc thực hiện pháp luật về phòng, chống tham nhũng", "ans": "d"}, {"num": 314, "q": "Thời hạn định kỳ chuyển đổi vị trí công tác là bao nhiêu năm?", "a": "Từ đủ 02 năm đến 05 năm theo đặc thù của từng ngành, lĩnh vực", "b": "Từ đủ 03 năm đến 06 năm theo đặc thù của từng ngành, lĩnh vực", "c": "Từ đủ 02 năm đến 04 năm theo đặc thù của từng ngành, lĩnh vực", "d": "Từ đủ 04 năm đến 05 năm theo đặc thù của từng ngành, lĩnh vực", "ans": "a"}, {"num": 315, "q": "Những người nào có nghĩa vụ kê khai tài sản?’", "a": "Cán bộ, công chức nhà nước", "b": "Sĩ quan Công an nhân dân; sĩ quan Quân đội nhân dân, quân nhân chuyên nghiệp", "c": "Người giữ chức vụ từ Phó trưởng phòng và tương đương trở lên công tác tại đơn vị sự nghiệp công lập, doanh nghiệp nhà nước, người được cử làm đại diện phần vốn nhà nước tại doanh nghiệp; Người ứng cử đại biểu Quốc hội, người ứng cử đại biểu Hội đồng nhân dân", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 316, "q": "Chọn phương án đúng nhất: Theo Luật Phòng, chống tham nhũng, người đứng đầu, cấp phó của người đứng đầu cơ quan, tổ chức, đơn vị không được bố trí những người nào dưới đây giữ chức vụ quản lý về tổ chức nhân sự, kế toán, làm thủ quỹ, thủ kho trong cơ quan, tổ chức, đơn vị hoặc giao dịch, mua bán hàng hóa, dịch vụ, ký kết hợp đồng cho cơ quan, tổ chức, đơn vị đó.", "a": "Vợ hoặc chồng", "b": "Vợ hoặc chồng, bố, mẹ, con, anh, chị, em ruột", "c": "Bố, mẹ, con, anh, chị, em ruột", "d": "Con, anh, chị, em ruột", "ans": "b"}, {"num": 317, "q": "Có bao nhiêu hình thức công khai về tổ chức và hoạt động của cơ quan, tổ chức, đơn vị?", "a": "5 hình thức", "b": "6 hình thức", "c": "7 hình thức", "d": "8 hình thức", "ans": "d"}, {"num": 318, "q": "Chọn đáp án đúng:", "a": "Cá nhân, tổ chức có quyền phản ánh, tố cáo về hành vi tham nhũng", "b": "Cá nhân, tổ chức có quyền phản ánh về hành vi tham nhũng, cá nhân có quyền tố cáo về hành vi tham nhũng theo quy định của pháp luật", "c": "Tổ chức có quyền phản ánh về hành vi tham nhũng, cá nhân có quyền tố cáo về hành vi tham nhũng theo quy định của pháp luật", "d": "Tất cả đáp án đều sai", "ans": "b"}, {"num": 319, "q": "Thế nào là vụ lợi?", "a": "Vụ lợi là hành vi của người có chức vụ, quyền hạn đã lợi dụng chức vụ, quyền hạn đó để tham nhũng", "b": "Vụ lợi là việc công chức lợi dụng chức vụ, quyền hạn nhằm đạt được lợi ích vật chất hoặc lợi ích phi vật chất không chính đáng", "c": "Vụ lợi là việc người có chức vụ, quyền hạn đã lợi dụng chức vụ, quyền hạn nhằm đạt được lợi ích vật chất hoặc lợi ích phi vật chất không chính đáng", "d": "Vụ lợi là hành vi lợi dụng chức vụ, quyền hạn đó để tham nhũng", "ans": "c"}, {"num": 320, "q": "Luật Phòng chống tham nhũng quy định việc tặng quà của cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn như thế nào?", "a": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn không được sử dụng tài chính công, tài sản công làm quà tặng, trừ trường hợp tặng quà vì mục đích từ thiện, đối ngoại và trong trường hợp cần thiết khác theo quy định của pháp luật.", "b": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn tuyệt đối không được sử dụng tài chính công, tài sản công làm quà tặng", "c": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn được sử dụng tài chính công, tài sản công làm quà tặng", "d": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn chỉ được sử dụng tài chính công, tài sản công làm quà tặng, vì mục đích từ thiện", "ans": "a"}, {"num": 321, "q": "Luật Phòng chống tham nhũng quy định việc nhận quà tặng của cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn như thế nào?", "a": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn được trực tiếp hoặc gián tiếp nhận quà tặng dưới mọi hình thức của cơ quan, tổ chức, đơn vị, cá nhân có liên quan đến công việc do mình giải quyết hoặc thuộc phạm vi quản lý của mình", "b": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn được trực tiếp nhận quà tặng dưới mọi hình thức của cơ quan, tổ chức, đơn vị, cá nhân có liên quan đến công việc do mình giải quyết hoặc thuộc phạm vi quản lý của mình", "c": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn được gián tiếp nhận quà tặng dưới mọi hình thức của cơ quan, tổ chức, đơn vị, cá nhân có liên quan đến công việc do mình giải quyết hoặc thuộc phạm vi quản lý của mình", "d": "Cơ quan, tổ chức, đơn vị, người có chức vụ, quyền hạn không được trực tiếp hoặc gián tiếp nhận quà tặng dưới mọi hình thức của cơ quan, tổ chức, đơn vị, cá nhân có liên quan đến công việc do mình giải quyết hoặc thuộc phạm vi quản lý của mình", "ans": "d"}, {"num": 322, "q": "Luật Phòng chống tham nhũng năm 2018 quy định việc xử lý tài sản tham nhũng như thế nào?", "a": "Tài sản tham nhũng phải được thu hồ theo quy định của pháp luật", "b": "Tài sản tham nhũng phải được trả lại cho chủ sở hữu, người quản lý hợp pháp theo quy định của pháp luật", "c": "Tài sản tham nhũng phải được tịch thu theo quy định của pháp luật", "d": "Tài sản tham nhũng phải được thu hồi, trả lại cho chủ sở hữu, người quản lý hợp pháp hoặc tịch thu theo quy định của pháp luật", "ans": "d"}, {"num": 323, "q": "Người kê khai tài sản, thu nhập phải có nghĩa vụ gì?", "a": "Người có nghĩa vụ kê khai phải kê khai tài sản, thu nhập và biến động về tài sản, thu nhập của mình", "b": "Người có nghĩa vụ kê khai phải kê khai tài sản, thu nhập và biến động về tài sản, thu nhập của mình, của vợ hoặc chồng", "c": "Người có nghĩa vụ kê khai phải kê khai tài sản, thu nhập và biến động về tài sản, thu nhập của mình, của vợ hoặc chồng, con chưa thành niên theo quy định của Luật này", "d": "Người có nghĩa vụ kê khai phải kê khai tài sản, thu nhập và biến động về tài sản, thu nhập của mình, con chưa thành niên", "ans": "c"}, {"num": 324, "q": "Trong phòng chống tham nhũng công tác kiểm tra của cơ quan, tổ chức, đơn vị bao gồm những hình thức nào?", "a": "Kiểm tra thường xuyên được tiến hành theo chương trình, kế hoạch và tập trung vào lĩnh vực, hoạt động dễ phát sinh tham nhũng", "b": "Chỉ kiểm tra đột xuất được tiến hành khi phát hiện có dấu hiệu tham nhũng", "c": "Kiểm tra thường xuyên được tiến hành theo chương trình, kế hoạch và tập trung vào lĩnh vực, hoạt động dễ phát sinh tham nhũng; kiểm tra đột xuất được tiến hành khi phát hiện có dấu hiệu tham nhũng", "d": "Kiểm tra thường xuyên và kiểm tra đột xuất", "ans": "c"}, {"num": 325, "q": "Khi phát hiện có hành vi tham nhũng, người đứng đầu cơ quan quản lý nhà nước phải làm gì?", "a": "kịp thời xử lý theo thẩm quyền hoặc báo cho cơ quan có thẩm quyền xử lý theo quy định của pháp luật", "b": "kịp thời xử lý theo thẩm quyền", "c": "báo cho cơ quan có thẩm quyền xử lý theo quy định của pháp luật", "d": "Họp cơ quan và xử lý nội bộ", "ans": "a"}, {"num": 326, "q": "Chọn đáp án đúng:", "a": "Người có hành vi tham nhũng giữ bất kì chức vụ, vị trí công tác nào đều phải bị xử lý nghiêm minh theo quy định của pháp luật, kể cả người đã nghỉ hưu, thôi việc, chuyển công tác", "b": "Người có hành vi tham nhũng giữ bất kì chức vụ, vị trí công tác nào đều phải bị xử lý nghiêm minh theo quy định của pháp luật, kể cả người đã thôi việc, chuyển công tác", "c": "Người có hành vi tham nhũng giữ bất kì chức vụ, vị trí công tác nào đều phải bị xử lý nghiêm minh theo quy định của pháp luật", "d": "Người có hành vi tham nhũng giữ bất kì chức vụ, vị trí công tác nào đều phải bị xử lý nghiêm minh theo quy định của pháp luật, kể cả người đã nghỉ hưu, chuyển công tác", "ans": "a"}, {"num": 327, "q": "Vi phạm hình sự ở mức độ tội phạm ít nghiêm trọng, khung hình cao nhất là…", "a": "7 năm", "b": "5 năm", "c": "3 năm", "d": "8 năm", "ans": "c"}, {"num": 328, "q": "Vi phạm hình sự ở mức độ tội phạm rất nghiêm trọng, khung hình cao nhất là…", "a": "7 năm", "b": "15 năm", "c": "3 năm", "d": "18 năm", "ans": "b"}, {"num": 329, "q": "Vi phạm hình sự ở mức độ tội phạm đặc biệt nghiêm trọng, khung hình cao nhất là…", "a": "20 năm", "b": "18 năm", "c": "15 năm", "d": "Tử hình", "ans": "d"}, {"num": 330, "q": "Những người có hành vi trái pháp luật sẽ bị cơ quan nhà nước có thẩm quyền xử lý theo quy định của pháp luật là thể hiện…?", "a": "mục đích và pháp luật", "b": "đặc trưng của pháp luật", "c": "bản chất của pháp luật", "d": "vai trò của pháp luật", "ans": "b"}, {"num": 331, "q": "Bạn A thắc mắc tại sao cả Hiến pháp và luật giáo dục đều quy định công dân có quyền và nghĩa vụ học tập? Em sẽ sử dụng đặc trưng nào dưới đây của pháp luật để giải thích cho bạn A?", "a": "tính quyền lực của pháp luật", "b": "tính xác định chặt chẽ về hình thức", "c": "tính quy phạm phổ biến của pháp luật", "d": "Tính bắt buộc chung của pháp luật", "ans": "b"}, {"num": 332, "q": "Để xử lý người có hành vi xâm hại đến các lợi ích của giai cấp cầm quyền, Nhà nước sẽ sử dụng quyền lực có tính cưỡng chế. Khẳng định này là nội dung nào dưới đây của pháp luật?", "a": "đặc trưng của pháp luật", "b": "bản chất của pháp luật", "c": "vai trò của pháp luật", "d": "chức năng của pháp luật", "ans": "b"}, {"num": 333, "q": "Pháp luật do nhà nước ban hành phù hợp với ý chí của giai cấp cầm quyền là thể hiện bản chất nào dưới đây của pháp luật?", "a": "chính trị", "b": "kinh tế", "c": "xã hội", "d": "giai cấp", "ans": "d"}, {"num": 334, "q": "Khi đạo đức trở thành nội dung của quy phạm pháp luật thì các giá trị đạo đức được nhà nước bảo đảm thực hiện bằng…", "a": "sức ép của dư luận xã hội", "b": "lương tâm của mỗi cá nhân", "c": "niềm tin của mọi người", "d": "sức mạnh quyền lực của nhà nước", "ans": "d"}, {"num": 335, "q": "Dựa vào nội dung nào dưới đây của pháp luật mà nhà nước có thể kiểm tra, kiểm soát được các hoạt động của mọi công dân?", "a": "đặc trưng của pháp luật", "b": "bản chất của pháp luật", "c": "chức năng của pháp luật", "d": "vai trò của pháp luật", "ans": "d"}, {"num": 336, "q": "Công dân có thể thực hiện quyền kinh doanh phù hợp với khả năng điều kiện của mình là biểu hiện vai trò nào dưới đây của pháp luật?", "a": "là phương tiện để nhà nước quản lý xã hội", "b": "là phương tiện để nhà nước phát huy quyền lực của mình", "c": "là phương tiện để công dân bảo vệ quyền và nghĩa vụ của mình", "d": "là phương tiện để công dân bảo vệ quyền và lợi ích hợp pháp của mình", "ans": "d"}, {"num": 337, "q": "Nhờ có luật sư tư vấn nên việc khiếu nại của gia đình ông B đã được giải quyết, trường hợp này đã thể hiện pháp luật là phương tiện để công dân bảo vệ quyền và…", "a": "nghĩa vụ của mình", "b": "trách nhiệm của mình", "c": "lợi ích hợp pháp của mình", "d": "nghĩa vụ hợp pháp của mình", "ans": "c"}, {"num": 338, "q": "Nhờ chị S có hiểu biết về pháp luật nên tranh chấp về đất đai giữa gia đình chị với gia đình anh B được giải quyết ổn thỏa, trường hợp này đã thể hiện vai trò nào dưới đây của pháp luật?", "a": "bảo vệ quyền và lợi ích hợp pháp của công dân", "b": "bảo vệ tự do ngôn luận và khiếu nại của công dân", "c": "bảo vệ quyền tự do dân chủ của công dân", "d": "bảo vệ quyền tham gia quản lý xã hội của công dân", "ans": "a"}, {"num": 339, "q": "Cửa hàng nhà A bị quản lý thị trường lập biên bản xử lý vì tiêu thụ thực phẩm bẩn, bạn X cho rằng, đặc trưng của pháp luật trong trường hợp này là tính quy phạm phổ biến; H thì khẳng định là tính quyền lực bắt buộc chung; Y nghe được liền nói đó vừa là tính quyền lực bắt buộc chung, vừa là tính xác định chặt chẽ về hình thức. Ý kiến của những ai dưới đây là đúng?", "a": "H và Y", "b": "Chỉ H đúng", "c": "X và H", "d": "X và Y", "ans": "c"}, {"num": 340, "q": "Hệ thống quy tắc xử sự chung do nhà nước ban hành và được bảo đảm thực hiện bằng…", "a": "quy định của nhà nước", "b": "quyền lực của nhà nước", "c": "chủ trương của nhà nước", "d": "chính sách của nhà nước", "ans": "b"}, {"num": 341, "q": "Mỗi quy tắc xử sự thường được thể hiện thành…", "a": "nhiều quy định pháp luật", "b": "một số quy định pháp luật", "c": "quy phạm pháp luật", "d": "nhiều quy phạm pháp luật", "ans": "c"}, {"num": 342, "q": "Giá trị công bằng bình đẳng của pháp luật được thể hiện rõ nhất ở đặc trưng nào dưới đây?", "a": "Tính chặt chẽ, cụ thể về nội dung", "b": "Tính xác định chặt chẽ về hình thức", "c": "Tính quyền lực, bắt buộc chung", "d": "Tính quy phạm phổ biến", "ans": "d"}, {"num": 343, "q": "Những người thực hiện không đúng quy định của pháp luật sẽ bị cơ quan có thẩm quyền áp dụng các biện pháp cần thiết để buộc họ phải tuân theo là thể hiện đặc trưng nào dưới đây của pháp luật?", "a": "Tính quy phạm phổ biến", "b": "Tính quyền lực bắt buộc chung", "c": "Tính hiệu lực tuyệt đối", "d": "Tính thực tiễn khả thi cao", "ans": "b"}, {"num": 344, "q": "Hình thức thể hiện của pháp luật là các văn bản có chứa…?", "a": "quy định chung", "b": "quy định bắt buộc", "c": "chuẩn mực chung", "d": "quy phạm pháp luật", "ans": "d"}, {"num": 345, "q": "Pháp luật mang bản chất giai cấp vì pháp luật do nhà nước ban hành…", "a": "phù hợp với ý chí của giai cấp cầm quyền", "b": "phù hợp với lợi ích của tất cả mọi người", "c": "bắt nguồn từ nhu cầu và lợi ích của nhân dân", "d": "bắt nguồn từ thực tiễn đời sống xã hội", "ans": "a"}, {"num": 346, "q": "Nội dung của văn bản do cơ quan cấp dưới ban hành trái với nội dung của văn bản do cơ quan cấp trên ban hành là vi phạm đặc trưng nào dưới đây của pháp luật?", "a": "trình tự ban hành quy phạm pháp luật", "b": "khả năng đảm bảo việc thi hành pháp luật", "c": "tính xác định chặt chẽ về mặt hình thức", "d": "hiệu lực tuyệt đối của văn bản pháp luật", "ans": "c"}, {"num": 347, "q": "Nội dung của tất cả các văn bản pháp luật đều phải phù hợp không được trái Hiến pháp đề cập đến đặc trưng nào dưới đây của pháp luật?", "a": "Tính xác định chặt chẽ về mặt hình thức", "b": "Tính xác định chi tiết về nội dung", "c": "Tính quyền lực bắt buộc chung", "d": "Tính khuôn mẫu, thuyết phục", "ans": "a"}, {"num": 348, "q": "Các quy phạm pháp luật do nhà nước ban hành phải phù hợp với…", "a": "nguyện vọng của mọi tầng lớp trong xã hội", "b": "nguyện vọng của giai cấp cầm quyền mà Nhà nước đại diện", "c": "Ý chí của giai cấp cầm quyền mà nhà nước là đại diện", "d": "Ý chí của mọi giai cấp và tầng lớp trong xã hội", "ans": "c"}, {"num": 349, "q": "Tại các thành phố, thị trấn nhiều người đi bộ ngang nhiên băng qua đường đi xuống lòng đường bất chấp quy tắc an toàn giao thông gây ra nhiều vụ tai nạn giao thông nghiêm trọng. Từ thực tế này, pháp luật tăng mức xử phạt đối với người đi bộ nếu vi phạm quy định khi tham gia giao thông đường bộ, quy định này thể hiện bản chất nào dưới đây của pháp luật?", "a": "bản chất văn hóa", "b": "bản chất xã hội", "c": "bản chất chính trị", "d": "bản chất giai cấp", "ans": "b"}, {"num": 350, "q": "Khẳng định nào dưới đây là không đúng khi nói về quan hệ giữa pháp luật với đạo đức?", "a": "quy phạm pháp luật chủ yếu thể hiện quan niệm về đạo đức", "b": "pháp luật là phương tiện đặc thù để thể hiện các giá trị đạo đức", "c": "pháp luật là phương tiện đặc thù để bảo vệ các giá trị đạo đức", "d": "pháp luật và đạo đức được thực hiện bằng quyền lực nhà nước", "ans": "d"}, {"num": 351, "q": "Điểm giống nhau cơ bản giữa pháp luật và đạo đức là…", "a": "điều chỉnh hành vi để hướng tới các giá trị xã hội", "b": "thể hiện những quy tắc mang tính bắt buộc chung", "c": "được tuân thủ bằng niềm tin, lương tâm của cá nhân", "d": "điều chỉnh hành vi dựa trên tính tự giác của công dân", "ans": "a"}, {"num": 352, "q": "Quyền tự do kinh doanh của công dân và nghĩa vụ của công dân khi thực hiện các hoạt động kinh doanh là nội dung cơ bản của pháp luật về….", "a": "phát triển kinh tế", "b": "phát triển văn hóa", "c": "phát triển các lĩnh vực xã hội", "d": "quốc phòng và an ninh", "ans": "a"}, {"num": 353, "q": "Quyền tự do kinh doanh được hiểu là mọi người được tự do…", "a": "kinh doanh khi có đủ các điều kiện vật chất", "b": "kinh doanh trong những ngành nghề pháp luật không cấm", "c": "quyết định thực hiện kinh doanh bất kỳ mặt hàng nào", "d": "quyết định mở rộng quy mô và hình thức kinh doanh", "ans": "b"}, {"num": 354, "q": "Quyền tự do kinh doanh có nghĩa là mọi công dân khi có đủ điều kiện do pháp luật quy định đều có quyền tiến hành hoạt động kinh doanh sau khi được cơ quan nhà nước có thẩm quyền…", "a": "tiếp nhận đăng ký kinh doanh", "b": "chấp nhận đăng ký kinh doanh", "c": "trả lại đăng ký kinh doanh", "d": "phản hồi về đăng ký kinh doanh", "ans": "b"}, {"num": 355, "q": "Nội dung nào dưới đây là điều kiện để công dân tiến hành hoạt động kinh doanh…", "a": "có đủ năng lực đăng ký kinh doanh", "b": "được cơ quan nhà nước có thẩm quyền chấp nhận đăng ký kinh doanh", "c": "có đủ điều kiện kinh tế để kinh doanh", "d": "có đủ tiềm lực kinh tế năng lực kinh doanh", "ans": "b"}, {"num": 356, "q": "Chủ thể nào dưới đây không được đăng ký kinh doanh…", "a": "người chưa thành niên", "b": "người thành niên", "c": "người có đủ điều kiện theo quy định của pháp luật", "d": "cán bộ công chức về hưu", "ans": "a"}, {"num": 357, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ mà người sản xuất kinh doanh phải thực hiện…", "a": "giải quyết việc làm cho lao động tại địa phương", "b": "bảo vệ môi trường", "c": "xóa đói giảm nghèo tại địa phương", "d": "đảm bảo đầy đủ điều kiện vật chất cho người lao động", "ans": "b"}, {"num": 358, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ của nhà sản xuất kinh doanh phải thực hiện…", "a": "giải quyết tình trạng thất nghiệp tại địa phương", "b": "xóa đói giảm nghèo tại địa phương", "c": "nộp thuế đầy đủ theo quy định của pháp luật", "d": "đảm bảo đầy đủ điều kiện vật chất cho người lao động", "ans": "c"}, {"num": 359, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ của nhà sản xuất kinh doanh….", "a": "kinh doanh đúng ngành nghề ghi trong giấy phép kinh doanh", "b": "xóa đói giảm nghèo tại địa phương", "c": "giải quyết việc làm cho lao động tại địa phương", "d": "đảm bảo đầy đủ điều kiện vật chất và tinh thần cho người lao động", "ans": "a"}, {"num": 360, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ của nhà sản xuất kinh doanh…", "a": "đảm bảo đầy đủ điều kiện vật chất cho người lao động", "b": "xóa đói giảm nghèo tại địa phương và vùng phụ cận", "c": "giải quyết việc làm cho lao động tại địa phương", "d": "bảo vệ quyền lợi người tiêu dùng", "ans": "d"}, {"num": 361, "q": "Nội dung nào dưới đây là một trong những nghĩa vụ của nhà sản xuất kinh doanh…", "a": "đảm bảo đầy đủ điều kiện vật chất cho người lao động", "b": "xóa đói giảm nghèo tại địa phương", "c": "tuân thủ các quy định về quốc phòng, an ninh", "d": "giải quyết việc làm cho lao động tại địa phương", "ans": "c"}, {"num": 362, "q": "Nghĩa vụ nào dưới đây rất quan trọng cần được nhà sản xuất kinh doanh thực hiện nghiêm chỉnh…", "a": "kinh doanh đúng ngành nghề ghi trong giấy phép", "b": "bảo vệ quyền lợi của nhân dân", "c": "nộp thuế đầy đủ theo quy định của pháp luật", "d": "tuân thủ các quy định về giao thông phòng chống tệ nạn xã hội", "ans": "a"}, {"num": 363, "q": "Các quy định pháp luật về giải quyết việc làm xóa đói giảm nghèo là nội dung của pháp luật về lĩnh vực…", "a": "chính trị", "b": "kinh tế", "c": "xã hội", "d": "văn hóa", "ans": "c"}, {"num": 364, "q": "Các quy định pháp luật nhằm kiềm chế sự gia tăng dân số và phòng chống tệ nạn xã hội là nội dung của pháp luật về lĩnh vực…", "a": "chính trị", "b": "kinh tế", "c": "xã hội", "d": "văn hóa", "ans": "c"}, {"num": 365, "q": "Biện pháp nào dưới đây được nhà nước sử dụng để xóa đói giảm nghèo…", "a": "chăm sóc sức khỏe cho nhân dân", "b": "tạo ra nhiều việc làm mới", "c": "mở rộng các hình thức trợ giúp người nghèo", "d": "phòng chống tệ nạn xã hội", "ans": "c"}, {"num": 366, "q": "Công dân có nghĩa vụ thực hiện kế hoạch hóa gia đình xây dựng gia đình ít con, no ấm, bình đẳng, tiến bộ hạnh phúc bền vững là nội dung được quy định trong…", "a": "Hiến pháp, Luật hôn nhân và gia đình", "b": "Hiến pháp, Pháp lệnh dân số", "c": "luật Hôn nhân và gia đình, Pháp lệnh dân số", "d": "pháp lệnh dân số", "ans": "c"}, {"num": 367, "q": "Đấu tranh phòng chống tội phạm, giữ gìn trật tự kỷ cương xã hội, ngăn chặn và bài trừ các tệ nạn xã hội nhất là nạn mại dâm, ma túy là nội dung được quy định trong…", "a": "Hiến pháp, Luật phòng chống ma túy", "b": "Hiến pháp, Pháp lệnh phòng chống mại dâm", "c": "Luật phòng chống ma túy, Pháp lệnh phòng chống mại dâm", "d": "Pháp lệnh phòng chống ma túy", "ans": "c"}, {"num": 368, "q": "Để bảo vệ môi trường những hành vi nào dưới đây bị pháp luật nghiêm cấm…", "a": "phá hoại, khai thác trái phép rừng, các nguồn tài nguyên thiên nhiên", "b": "bảo tồn và sử dụng hợp lý tài nguyên thiên nhiên", "c": "bảo vệ môi trường rừng và các tài nguyên thiên nhiên", "d": "không săn bắt động vật quý hiếm", "ans": "a"}, {"num": 369, "q": "Quá trình hoạt động có mục đích, làm cho các quy định của pháp luật đi vào cuộc sống và trở thành những hành vi hợp pháp của các cá nhân, tổ chức là nội dung của khái niệm nào dưới đây?", "a": "ban hành pháp luật", "b": "xây dựng pháp luật", "c": "thực hiện pháp luật", "d": "phổ biến pháp luật", "ans": "c"}, {"num": 370, "q": "Công dân khi tham gia các quan hệ xã hội đều thực hiện cách xử sự phù hợp với quy định của pháp luật là biểu hiện của…", "a": "ban hành pháp luật", "b": "xây dựng pháp luật", "c": "thực hiện pháp luật", "d": "phổ biến pháp luật", "ans": "c"}, {"num": 371, "q": "Mục đích của việc ban hành pháp luật là điều chỉnh cách xử sự của công dân theo các quy tắc, cách thức phù hợp với yêu cầu của chủ thể nào dưới đây?", "a": "tổ chức", "b": "cộng đồng", "c": "nhà nước", "d": "xã hội", "ans": "c"}, {"num": 372, "q": "Thực hiện pháp luật là quá trình hoạt động có mục đích, làm cho các quy định của pháp luật đi vào cuộc sống trở thành hành vi…", "a": "có ích của công dân", "b": "cơ bản của cá nhân", "c": "hợp pháp của công dân", "d": "cốt lõi của cá nhân", "ans": "c"}, {"num": 373, "q": "Nội dung nào dưới đây không phải là biểu hiện của thực hiện pháp luật…", "a": "làm những việc mà pháp luật cho phép làm", "b": "làm những việc mà pháp luật quy định phải làm", "c": "không làm những việc mà pháp luật cấm", "d": "làm những việc mà pháp luật cấm", "ans": "d"}, {"num": 374, "q": "Các cá nhân, tổ chức sử dụng đúng đắn các quyền của mình làm những gì mà pháp luật cho phép làm là nội dung của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 375, "q": "Công dân chủ động làm những gì mà pháp luật quy định phải làm là hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "b"}, {"num": 376, "q": "Hình thức thực hiện pháp luật nào dưới đây mà chủ thể có quyền lựa chọn làm hoặc không làm?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 377, "q": "Công dân được làm những gì mà pháp luật cho phép làm là nội dung của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 378, "q": "Các cá nhân, tổ chức thực hiện đầy đủ những nghĩa vụ, chủ động làm những gì mà pháp luật quy định phải làm là hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "b"}, {"num": 379, "q": "Sử dụng pháp luật được hiểu là công dân sử dụng đúng đắn các quyền của mình làm những gì mà pháp luật…", "a": "không cho phép làm", "b": "cho phép làm", "c": "quy định cấm làm", "d": "quy định phải làm", "ans": "b"}, {"num": 380, "q": "Thi hành pháp luật là việc các cá nhân tổ chức…", "a": "chủ động làm những gì mà pháp luật quy định phải làm", "b": "chủ động không làm những gì mà pháp luật cấm", "c": "tự giác làm những gì mà pháp luật cho phép làm", "d": "tự giác thực hiện những gì mà pháp luật quy định nên làm", "ans": "a"}, {"num": 381, "q": "Thi hành pháp luật được hiểu là các cá nhân tổ chức thực hiện đầy đủ những nghĩa vụ, chủ động làm những gì mà pháp luật…", "a": "quy định nên làm", "b": "không cấm", "c": "Quy định phải làm", "d": "cho phép làm", "ans": "c"}, {"num": 382, "q": "Tuân thủ pháp luật được hiểu là việc các cá nhân tổ chức…", "a": "làm những điều mà pháp luật cho phép", "b": "làm những điều mà pháp luật bắt buộc", "c": "không làm những điều mà pháp luật cấm", "d": "không làm những điều mà pháp luật ràng buộc", "ans": "c"}, {"num": 383, "q": "Việc các cá nhân tổ chức không làm những điều mà pháp luật cấm là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "c"}, {"num": 384, "q": "Áp dụng pháp luật được hiểu là các cơ quan công chức nhà nước có thẩm quyền ra các quyết định làm phát sinh chấm dứt hoặc thay đổi việc thực hiện…", "a": "quyền và trách nhiệm cụ thể của công dân", "b": "quyền và nghĩa vụ cụ thể của công dân", "c": "nghĩa vụ và lợi ích cụ thể của công dân", "d": "nghĩa vụ và quyền lợi cụ thể của công dân", "ans": "b"}, {"num": 385, "q": "Cơ quan công chức nhà nước có thẩm quyền ban hành các quyết định trong quản lý điều hành là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 386, "q": "Hình thức thực hiện pháp luật nào dưới đây có chủ thể thực hiện khác với các hình thức còn lại?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 387, "q": "Việc các cơ quan công chức nhà nước có thẩm quyền ra quyết định làm phát sinh chấm dứt hoặc thay đổi việc thực hiện các quyền, nghĩa vụ cụ thể của công dân là nội dung của hình thức thực hiện pháp luật nào dưới đây?", "a": "Tuân thủ pháp luật", "b": "Thi hành pháp luật", "c": "Sử dụng pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 388, "q": "Tuân thủ pháp luật là hình thức thực hiện pháp luật trong đó các cá nhân tổ chức không làm những điều mà pháp luật…?", "a": "cho phép làm", "b": "quy định cấm", "c": "quy định phải làm", "d": "không bắt buộc", "ans": "b"}, {"num": 389, "q": "Hành vi trái pháp luật, có lỗi do người có năng lực trách nhiệm pháp lý thực hiện xâm hại các quan hệ xã hội được pháp luật bảo vệ là nội dung của khái niệm nào dưới đây?", "a": "Thực hiện pháp luật", "b": "Vi phạm pháp luật", "c": "Tuân thủ pháp luật", "d": "Trách nhiệm pháp lý", "ans": "b"}, {"num": 390, "q": "Dấu hiệu nào dưới đây không phải là một trong những căn cứ để xác định một hành vi vi phạm pháp luật…?", "a": "hành vi chứa đựng lỗi của chủ thể thực hiện", "b": "hành vi do người có năng lực trách nhiệm pháp lý thực hiện", "c": "hành vi do người có thẩm quyền thực hiện theo quy định của pháp luật", "d": "hành vi xâm hại các quan hệ xã hội được pháp luật bảo vệ", "ans": "c"}, {"num": 391, "q": "Một trong những căn cứ để xác định một hành vi vi phạm pháp luật là hành vi do người…", "a": "có năng lực trách nhiệm pháp lý thực hiện", "b": "có thẩm quyền trong cơ quan nhà nước thực hiện", "c": "trên 18 tuổi thực hiện", "d": "từ trên 16 tuổi đến 18 tuổi thực hiện", "ans": "a"}, {"num": 392, "q": "Dấu hiệu nào dưới đây là một trong những căn cứ để xác định hành vi trái pháp luật?", "a": "hành vi xâm hại các chuẩn mực xã hội", "b": "hành vi xâm hại các phong tục tập quán", "c": "hành vi xâm hại các quy định của xã hội", "d": "hành vi xâm hại quan hệ xã hội pháp luật bảo vệ", "ans": "d"}, {"num": 393, "q": "Năng lực trách nhiệm pháp lý của cá nhân bao gồm…?", "a": "độ tuổi và nhận thức", "b": "độ tuổi và trình độ", "c": "độ tuổi và hành vi", "d": "trình độ và hành vi", "ans": "d"}, {"num": 394, "q": "Dấu hiệu nào dưới đây là biểu hiện của hành vi trái pháp luật?", "a": "công dân làm những việc pháp luật quy định không được làm", "b": "công dân không làm những việc mà pháp luật cấm", "c": "công dân làm những việc mà pháp luật cho phép làm", "d": "công dân làm những việc phải làm theo quy định pháp luật", "ans": "a"}, {"num": 395, "q": "Hành vi trái pháp luật nào dưới đây do người có năng lực trách nhiệm pháp lý thực hiện?", "a": "Anh A trong lúc say rượu đánh bạn mình bị thương nặng", "b": "Em H bị tâm thần nên đã lấy đồ của cửa hàng mà không trả tiền", "c": "Chị A bị trầm cảm nên đã sát hại con đẻ của mình", "d": "Anh T trong lúc lên cơn động kinh đã đập vỡ cửa kính nhà hang", "ans": "a"}, {"num": 396, "q": "Trường hợp nào dưới đây chủ thể không vi phạm pháp luật?", "a": "cháu hát bị trói tay và bị đổ ma túy đá vào miệng", "b": "anh B phát hiện kẻ móc túi nhưng không báo với ai", "c": "chị L che dấu hành vi buôn bán ma túy của người thân trong gia đình", "d": "cảnh sát giao thông không xử phạt vi phạm của anh T vì quen biết", "ans": "a"}, {"num": 397, "q": "Nghĩa vụ mà các cá nhân hoặc tổ chức phải gánh chịu hậu quả bất lợi từ hành vi vi phạm pháp luật của mình là nội dung của khái niệm nào dưới đây?", "a": "trách nhiệm pháp lý", "b": "nghĩa vụ pháp lý", "c": "vi phạm pháp luật", "d": "thực hiện pháp luật", "ans": "a"}, {"num": 398, "q": "Anh A đi xe máy phóng nhanh vượt ẩu nên đâm vào người đi đường làm họ bị chấn thương, tổn hại sức khỏe là 31% và xe máy bị hỏng nặng, trường hợp này anh A phải chịu những loại trách nhiệm pháp lý nào dưới đây?", "a": "Hình sự và hành chính", "b": "Dân sự và hành chính", "c": "Hình sự và dân sự", "d": "Kỷ luật và dân sự", "ans": "c"}, {"num": 399, "q": "Hành vi nào dưới đây phải chịu trách nhiệm hình sự?", "a": "cố ý lây truyền HIV cho người khác", "b": "điều khiển xe máy đi ngược chiều của của đường một chiều", "c": "không thực hiện chia tài sản theo di chúc của người mất", "d": "lấy trộm ví tiền giá trị 450.000 đồng", "ans": "a"}, {"num": 400, "q": "Người từ đủ 14 tuổi đến dưới 16 tuổi phải chịu trách nhiệm hình sự về…", "a": "mọi tội phạm", "b": "tội phạm nghiêm trọng do vô ý", "c": "tội phạm đặc biệt nghiêm trọng", "d": "tội phạm do lỗi cố ý", "ans": "c"}, {"num": 401, "q": "Người có hành vi vi phạm hình sự trước hết phải chịu trách nhiệm…", "a": "Hình sự", "b": "Hành chính", "c": "Dân sự", "d": "Kỷ luật", "ans": "a"}, {"num": 402, "q": "Vi phạm hành chính là những hành vi xâm phạm…", "a": "kỷ luật lao động", "b": "kỷ luật của tổ chức", "c": "quy tắc quản lý nhà nước", "d": "quy tắc quản lý hành chính", "ans": "c"}, {"num": 403, "q": "Hình thức khiển trách cảnh cáo chuyển công tác khác khi xâm phạm các quan hệ công vụ nhà nước do pháp luật hành chính bảo vệ được áp dụng với người có hành vi nào dưới đây?", "a": "vi phạm hành chính", "b": "vi phạm dân sự", "c": "vi phạm hình sự", "d": "vi phạm kỷ luật", "ans": "d"}, {"num": 404, "q": "Vi phạm dân sự là những hành vi vi phạm pháp luật xâm phạm tới quan hệ nào dưới đây?", "a": "quan hệ sở hữu và quan hệ nhân thân", "b": "quan hệ sở hữu và quan hệ tình cảm", "c": "quan hệ tài sản và quan hệ tình cảm", "d": "quan hệ tài sản và quan hệ nhân thân", "ans": "d"}, {"num": 405, "q": "Bồi thường thiệt hại về vật chất khi có các hành vi xâm phạm tới các quan hệ tài sản và quan hệ nhân thân được áp dụng với những hành vi vi phạm…?", "a": "hành chính", "b": "dân sự", "c": "hình sự", "d": "kỷ luật", "ans": "b"}, {"num": 406, "q": "Vi phạm hành chính là những hành vi vi phạm quy định của pháp luật về quản lý Nhà nước do…?", "a": "tổ chức kinh tế thực hiện", "b": "tổ chức chính trị thực hiện", "c": "cá nhân thực hiện", "d": "cá nhân hoặc tổ chức thực hiện", "ans": "d"}, {"num": 407, "q": "Cơ quan X bị mất một số tài sản do bảo vệ cơ quan quên không khóa cổng, vậy bảo vệ cơ quan này phải chịu trách nhiệm pháp lý nào dưới đây?", "a": "trách nhiệm hình sự", "b": "trách nhiệm dân sự", "c": "trách nhiệm hành chính", "d": "trách nhiệm kỷ luật", "ans": "d"}, {"num": 408, "q": "Hành vi không lạng lách đánh võng khi đi xe máy trên đường của anh A là biểu hiện hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Tuân thủ pháp luật", "c": "Thi hành pháp luật", "d": "Áp dụng pháp luật", "ans": "b"}, {"num": 409, "q": "Cảnh sát giao thông xử phạt người chở hàng cồng kềnh khi tham gia giao thông là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Thi hành pháp luật", "c": "Tuân thủ pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 410, "q": "Anh M sử dụng điện thoại di động khi đang điều khiển xe máy. Công an đã xử phạt hành chính anh M việc làm của công an là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Tuân thủ pháp luật", "b": "Sử dụng pháp luật", "c": "Thi hành pháp luật", "d": "Áp dụng pháp luật", "ans": "d"}, {"num": 411, "q": "Hành vi không đội mũ bảo hiểm khi tham gia giao thông trên đường của người điều khiển người ngồi trên xe mô tô là vi phạm hình thức thực hiện pháp luật nào dưới đây?", "a": "Tuân thủ pháp luật", "b": "Thi hành pháp luật", "c": "Sử dụng pháp luật", "d": "Áp dụng pháp luật", "ans": "a"}, {"num": 412, "q": "Chị M điều khiển xe máy vượt quá tốc độ cho phép nên đã bị cảnh sát giao thông X lập biên bản và xử phạt hành chính, hành vi của cảnh sát giao thông X là biểu hiện của hình thức thực hiện pháp luật nào dưới đây?", "a": "Sử dụng pháp luật", "b": "Áp dụng pháp luật", "c": "Thi hành pháp luật", "d": "Tuân thủ pháp luật", "ans": "b"}, {"num": 413, "q": "Hành vi phạm tội nào không phải xảy ra trên lãnh thổ Việt Nam sau đây?", "a": "Hành vi phạm tội bắt đầu trên lãnh thổ Việt Nam", "b": "Hành vi phạm tội diễn ra trên lãnh thổ Việt Nam", "c": "Hành vi phạm tội kết thúc trên lãnh thổ Việt Nam", "d": "Hành vi phạm tội không thuộc một trong các trường hợp đã nêu", "ans": "d"}, {"num": 414, "q": "Nhận định nào dưới đây về luật hình sự không đúng?", "a": "Là một văn bản trong hệ thống pháp luật của nước Cộng hoà xã hội chủ nghĩa Việt Nam", "b": "Là một ngành luật trong hệ thống pháp luật của nước Cộng hoà xã hội chủ nghĩa Việt Nam", "c": "Bao gồm hệ thống những quy phạm pháp luật do Nhà nước ban hành", "d": "Xác định những hành vi nguy hiểm nào cho xã hội là tội phạm, đồng thời quy định hình phạt đối với những tội phạm ấy", "ans": "a"}, {"num": 415, "q": "Luật hình sự có những nguyên tắc nào dưới đây?", "a": "Nguyên tắc pháp chế XHCN", "b": "Nguyên tắc dân chủ XHCN", "c": "Nguyên tắc phân hóa trách nhiệm hình sự", "d": "Tất cả đều đúng", "ans": "d"}, {"num": 416, "q": "Yếu tố nào sau đây là một trong những dấu hiệu cơ bản (đặc điểm) của tội phạm?", "a": "Trái với đạo đức xã hội", "b": "Vi phạm pháp luật", "c": "Phải đươc quy định trong Bộ luật Hình sự", "d": "Phải được quy định trong các văn bản quy phạm pháp luật", "ans": "c"}, {"num": 417, "q": "Đâu là loại tội phạm nghiêm trọng?", "a": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội không lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là phạt tiền, phạt cải tạo không giam giữ hoặc phạt tù đến 03 năm", "b": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 03 năm tù đến 07 năm tù", "c": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội rất lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 07 năm tù đến 15 năm tù", "d": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội đặc biệt lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 15 năm tù đến 20 năm tù, tù chung thân hoặc tử hình", "ans": "b"}, {"num": 418, "q": "Đâu là loại tội phạm rất nghiêm trọng?", "a": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội không lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là phạt tiền, phạt cải tạo không giam giữ hoặc phạt tù đến 03 năm", "b": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 03 năm tù đến 07 năm tù", "c": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội rất lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 07 năm tù đến 15 năm tù", "d": "là tội phạm có tính chất và mức độ nguy hiểm cho xã hội đặc biệt lớn mà mức cao nhất của khung hình phạt do Bộ luật này quy định đối với tội ấy là từ trên 15 năm tù đến 20 năm tù, tù chung thân hoặc tử hình", "ans": "c"}, {"num": 419, "q": "Cố ý phạm tội là phạm tội trong những trường hợp sau đây?", "a": "Người phạm tội tuy thấy trước hành vi của mình có thể gây ra hậu quả nguy hại cho xã hội nhưng cho rằng hậu quả đó sẽ không xảy ra hoặc có thể ngăn ngừa được", "b": "Người phạm tội không thấy trước hành vi của mình có thể gây ra hậu quả nguy hại cho xã hội, mặc dù phải thấy trước và có thể thấy trước hậu quả đó", "c": "Người phạm tội nhận thức rõ hành vi của mình là nguy hiểm cho xã hội, không thấy trước hậu quả của hành vi đó có thể xảy ra, tuy không mong muốn nhưng vẫn có ý thức để mặc cho hậu quả xảy ra", "d": "Người phạm tội nhận thức rõ hành vi của mình là nguy hiểm cho xã hội, thấy trước hậu quả của hành vi đó và mong muốn hậu quả xảy ra", "ans": "d"}, {"num": 420, "q": "Vô ý phạm tội là phạm tội trong những trường hợp sau đây?", "a": "Người phạm tội không thấy trước hành vi của mình có thể gây ra hậu quả nguy hại cho xã hội vì vậy cho rằng hậu quả đó sẽ không xảy ra hoặc có thể ngăn ngừa được", "b": "Người phạm tội không thấy trước hành vi của mình có thể gây ra hậu quả nguy hại cho xã hội, mặc dù phải thấy trước và có thể thấy trước hậu quả đó", "c": "Người phạm tội nhận thức rõ hành vi của mình là nguy hiểm cho xã hội, thấy trước hậu quả của hành vi đó có thể xảy ra, tuy không mong muốn nhưng vẫn có ý thức để mặc cho hậu quả xảy ra", "d": "Người phạm tội nhận thức rõ hành vi của mình là nguy hiểm cho xã hội, thấy trước hậu quả của hành vi đó và mong muốn hậu quả xảy ra", "ans": "b"}, {"num": 421, "q": "Cơ sở của trách nhiệm hình sự là:", "a": "Hành vi được Viện kiểm sát cho phạm tội thì phải chịu trách nhiệm sự", "b": "Có hành vi gây nguy hiểm thì phải chịu trách nhiệm hình sự", "c": "Phạm tội gây thiệt hại vật chất cho người khác phải chịu trách nhiệm hình sự", "d": "Người nào phạm một tội đã được Bộ luật Hình sự quy định mới phải chịu trách nhiệm hình sự", "ans": "d"}, {"num": 422, "q": "Đâu là dấu hiệu của tội phạm?", "a": "hành vi nguy hiểm cho xã hội được quy định trong Bộ luật Hình sự", "b": "hành vi tuy có dấu hiệu của tội phạm nhưng tính chất nguy hiểm cho xã hội không đáng kể", "c": "hành vi nguy hiểm do người có năng lực hành vi dân sự thực hiện một cách cố ý hoặc vô ý", "d": "Có hành vi nguy hiểm", "ans": "a"}, {"num": 423, "q": "Căn cứ vào tính chất và mức độ nguy hiểm cho xã hội của hành vi phạm tội được quy định trong Bộ luật Hình sự, tội phạm được phân thành mấy loại?", "a": "03 loại", "b": "04 loại", "c": "05 loại", "d": "06 loại", "ans": "b"}, {"num": 424, "q": "Nghĩa vụ người lao động, người sử dụng lao động trong việc giải quyết tranh chấp lao động:", "a": "Cung cấp đầy đủ tài liệu cho cơ quan có thẩm quyền và thi hành mọi quyết định giải quyết tranh chấp của các cơ quan, tổ chức có thẩm quyền", "b": "Cung cấp đầy đủ tài liệu, thi hành mọi quyết định của cơ quan, tổ chức có thẩm quyền giải quyết tranh chấp", "c": "Cung cấp đầy đủ tài liệu chứng cứ cho cơ quan giải quyết tranh chấp. Thi hành mọi thoả thuận đã đạt, biên bản hoà giải có kết quả, quyết định, bản án đã có hiệu lực", "d": "Cung cấp đầy đủ mọi chứng cứ, tài liệu cho các cơ quan có thẩm quyền, thi hành tốt mọi quyết định giải quyết tranh chấp của cơ quan có thẩm quyền", "ans": "c"}, {"num": 425, "q": "Quyền của người lao động, người sử dụng lao động trong việc giải quyết tranh chấp lao động:", "a": "Tham gia trực tiếp hoặc rút đơn không tham gia giải quyết tranh chấp. Có thể cử người đại diện thay mình tham gia quá trình giải quyết tranh chấp", "b": "Trực tiếp hoặc cử đại diện tham gia giải quyết tranh chấp – Rút đơn, thay đổi nội dung tranh chấp, thay người đại diện", "c": "Trực tiếp tham gia giải quyết tranh chấp hoặc cử đại diện tham giA. Rút đơn không tham gia giải quyết tranh chấp nữa", "d": "Trực tiếp tham gia hoặc cử đại diện tham gia hoặc thay đổi người đại diện hoặc rút đơn không tham gia giải quyết tranh chấp nữa", "ans": "b"}, {"num": 426, "q": "Hình thức sa thải người lao động chỉ được áp dụng trong trường hợp nào?", "a": "Người lao động tự ý bỏ việc không có lý do chính đáng, đang bị xử một hình thức kỷ luật mà tái phạm, trộm cắp, tham ô tài sản của doanh nghiệp", "b": "Trộm cắp, tham ô, tiết lộ bí mật công nghệ – kinh doanh của doanh nghiệp, đang bị kỷ luật chuyển làm việc khác lại tái phạm, tự ý bỏ việc", "c": "Người lao động tự ý bỏ việc 7 ngày 1 tháng, 20 ngày 1 năm không có lý do chính đáng, trộm cắp tham ô, tiết lộ bí mật của doanh nghiệp, đang bị kỷ luật chuyển làm việc khác lại tái phạm", "d": "Người lao động tự ý bỏ việc từ 7 đến 20 ngày không có lý do chính đáng, trộm cắp, tiết lộ bí mật, tái phạm nhiều lần mà không xử", "ans": "c"}, {"num": 427, "q": "Người sử dụng lao động có nghĩa vụ gì đối với người lao động cao tuổi làm việc tại cơ sở của mình?", "a": "Áp dụng chế độ làm việc mềm dẻo trong một năm trước khi nghỉ hưu. Nếu hưu vẫn tiếp tục làm hợp đồng thì ngoài chế độ hợp đồng mới, vẫn hưởng mọi chế độ như khi chưa hưu (trừ lương)", "b": "Áp dụng thì giờ làm việc mềm dẻo trong một năm trước khi nghỉ hưu. Có thể tiếp tục sử dụng những người lưu theo chế độ hợp đồng lao động mới", "c": "Áp dụng chế độ và thời giờ làm việc mềm dẻo, một ngày không làm trọn 8 tiếng, một tuần không làm quá 35 tiếng", "d": "Áp dụng thời giờ làm việc mềm dẻo, một ngày không làm quá 7 tiếng, 1 tuần không làm trọn 5 ngày", "ans": "a"}, {"num": 428, "q": "Người sử dụng lao động có nghĩa vụ gì đối với lao động chưa thành niên làm việc ở cơ sở mình?", "a": "Giao việc phù hợp với sức khoẻ, có sổ theo dõi riêng, một ngày làm việc không quá 7 tiếng", "b": "Lao động chưa thành niên là người chưa đến 18 tuổi nên chỉ được giao 1 số việc theo quy định của Bộ Lao động", "c": "Giao việc phù hợp với sức khoẻ, chỉ giao 1 số việc theo quy định của Bộ Lao động, có sổ theo dõi riêng", "d": "Chỉ được giao công việc theo đúng quy định của Bộ Lao động và có sổ theo dõi riêng", "ans": "a"}, {"num": 429, "q": "Theo Luật Lao động, tiền lương của người lao động được trả như thế nào?", "a": "Do hai bên thoả thuận trong hợp đồng, mức lương không được thấp hơn mức lương tối thiểu do Nhà nước quy định", "b": "Trả theo năng suất lao động, chất lượng, hiệu quả công việc, do hai bên thoả thuận", "c": "Trả theo năng suất, chất lượng, hiệu quả công việc, mức lương không thể thấp hơn mức tối thiểu do Nhà nước quy định", "d": "Theo năng suất, chất lượng, hiệu quả công việc do hai bên thoả thuận trong hợp đồng nhưng không được thấp hơn mức tối thiểu do Nhà nước quy định", "ans": "d"}, {"num": 430, "q": "Cách thức giải quyết tranh chấp lao động:", "a": "Hai bên tự dàn xếp, thương lượng trực tiếp, thông qua trọng tài hoà giải", "b": "Thương lượng trực tiếp, thông qua trọng tài hoà giải, tham gia của công đoàn", "c": "Thương lượng trực tiếp, tham gia của công đoàn, thông qua trọng tài hoà giải", "d": "Thương lượng trực tiếp, tham gia của công đoàn, công khai, khách quan, kịp thời, thông qua trọng tài hoà giải", "ans": "d"}];
